import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useThree, ThreeEvent } from '@react-three/fiber';
import { GridCoord, ShapeType, CellType, BlueprintCell } from '../../domain/types';
import { 
  Color, Matrix4, BoxGeometry, 
  MeshStandardMaterial, InstancedMesh 
} from 'three';
import { EditorTool } from '../../App';

// COLORS
const COL_BODY = new Color('#3b82f6'); // Blue
const COL_HEAD = new Color('#ef4444'); // Red
const COL_FOOT = new Color('#22c55e'); // Green

export const BlueprintView: React.FC<{
    cells: BlueprintCell[]; 
    onCellClick: (x: number, y: number, z: number, isRight: boolean) => void;
    currentType: ShapeType;
    editorTool: EditorTool;
    brushType: CellType;
}> = ({ cells, onCellClick, currentType, editorTool, brushType }) => {

  const { camera, raycaster, pointer, scene } = useThree();
  const [hoverCoord, setHoverCoord] = useState<GridCoord | null>(null);

  // INSTANCING REFS
  const meshRef = useRef<InstancedMesh>(null);
  const tempMat = useMemo(() => new Matrix4(), []);

  const boxGeo = useMemo(() => new BoxGeometry(0.8, 0.8, 0.8), []);

  // Materials
  const hoverMaterial = useMemo(() => new MeshStandardMaterial({ 
      color: '#ffffff', transparent: true, opacity: 0.6 
  }), []);
  const eraseMaterial = useMemo(() => new MeshStandardMaterial({ color: '#ef4444', transparent: true, opacity: 0.5 }), []);

  // UPDATE INSTANCES
  useEffect(() => {
      if (!meshRef.current) return;

      meshRef.current.count = cells.length;

      cells.forEach((c, i) => {
          tempMat.identity();
          // Standard Cartesian
          tempMat.setPosition(c.x, c.y, c.z);

          meshRef.current!.setMatrixAt(i, tempMat);

          // SET COLOR BASED ON CELL TYPE
          if (c.type === CellType.HEAD) meshRef.current!.setColorAt(i, COL_HEAD);
          else if (c.type === CellType.FOOT) meshRef.current!.setColorAt(i, COL_FOOT);
          else meshRef.current!.setColorAt(i, COL_BODY);
      });
      meshRef.current.instanceMatrix.needsUpdate = true;
      if (meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;

      if (meshRef.current.geometry) {
          meshRef.current.computeBoundingSphere();
      }

  }, [cells, currentType, tempMat]);

  // Handle ghost color update
  useEffect(() => {
      if (editorTool === 'ERASE') return;
      if (brushType === CellType.HEAD) hoverMaterial.color.set(COL_HEAD);
      else if (brushType === CellType.FOOT) hoverMaterial.color.set(COL_FOOT);
      else hoverMaterial.color.set(COL_BODY);
  }, [brushType, hoverMaterial, editorTool]);

  // --- EVENTS ON MESH ---

  const handleMeshMove = (e: ThreeEvent<PointerEvent>) => {
      e.stopPropagation();
      if (editorTool === 'VIEW') return;

      const instanceId = e.instanceId;
      if (instanceId === undefined) return;

      const c = cells[instanceId];
      if (!c) return;

      if (editorTool === 'ERASE') {
          setHoverCoord(c);
      } 
      else if (editorTool === 'BUILD') {
         // Standard Cube Logic (Normals)
         if (e.face) {
             const n = e.face.normal;
             setHoverCoord({
                 x: c.x + Math.round(n.x),
                 y: c.y + Math.round(n.y),
                 z: c.z + Math.round(n.z)
             });
         }
      }
  };

  const handleMeshClick = (e: ThreeEvent<MouseEvent>) => {
      e.stopPropagation();
      if (editorTool === 'VIEW') return;

      const instanceId = e.instanceId;
      if (instanceId === undefined) return;

      if (editorTool === 'ERASE') {
          const c = cells[instanceId];
          if (c) onCellClick(c.x, c.y, c.z, true);
      }
      else if (editorTool === 'BUILD') {
          if (hoverCoord) {
              onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false);
          }
      }
  };

  const handleFloorMove = (e: ThreeEvent<PointerEvent>) => {
      if (editorTool !== 'BUILD') {
          if (editorTool !== 'ERASE') setHoverCoord(null);
          return;
      }
      e.stopPropagation();

      const hitPoint = e.point;

      setHoverCoord({
          x: Math.round(hitPoint.x),
          y: 0,
          z: Math.round(hitPoint.z)
      });
  };

  const handleFloorClick = (e: ThreeEvent<MouseEvent>) => {
       if (editorTool !== 'BUILD') return;
       e.stopPropagation();
       if (hoverCoord) {
           onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false);
       }
  };

  const handleMiss = () => {
     setHoverCoord(null);
  };

  return (
    <group onPointerMissed={handleMiss}>
      <ambientLight intensity={0.8} />
      <directionalLight position={[5, 10, 5]} intensity={1.5} />

      <instancedMesh 
          ref={meshRef} 
          args={[undefined, undefined, 2000]} 
          onPointerMove={handleMeshMove}
          onClick={handleMeshClick}
          onContextMenu={handleMeshClick}
      >
          <boxGeometry args={[0.8, 0.8, 0.8]} />
          <meshStandardMaterial color="#ffffff" roughness={0.3} />
      </instancedMesh>

      {hoverCoord && (
         <group>
             <mesh 
                position={[hoverCoord.x, hoverCoord.y, hoverCoord.z]} 
                geometry={boxGeo} 
                material={editorTool === 'ERASE' ? eraseMaterial : hoverMaterial} 
                raycast={() => null}
             />
         </group>
      )}

      <mesh 
          rotation={[-Math.PI / 2, 0, 0]} 
          position={[0, -0.01, 0]} 
          name="base_plane" 
          visible={false}
          onPointerMove={handleFloorMove}
          onClick={handleFloorClick}
      >
          <planeGeometry args={[100, 100]} />
      </mesh>

      <gridHelper args={[40, 40, 0x444444, 0x222222]} position={[0, -0.01, 0]} />
    </group>
  );
};

import { useEffect, useRef, useState, useCallback } from 'react';
import { EvolutionService } from './EvolutionService';
import { ShapeType, Organism } from '../domain/types';

export function useEvolutionLoop() {
  const serviceRef = useRef<EvolutionService>(new EvolutionService());
  const requestRef = useRef<number>(0);

  const [population, setPopulation] = useState<Organism[]>([]);
  const [generation, setGeneration] = useState(1);
  const [currentShape, setCurrentShape] = useState<ShapeType>(ShapeType.CUBE);
  const [isRunning, setIsRunning] = useState(false);
  const [isFastForward, setIsFastForward] = useState(false);

  // STATS STATE - OPTIMIZED: We now share a REF, not a state, for high frequency updates
  const [fitnessHistory, setFitnessHistory] = useState<number[]>([]);
  const statsRef = useRef({ fitness: 0, foodEaten: 0, distance: 0 });

  // New Physics State (Updated Defaults)
  const [globalStiffness, setGlobalStiffnessState] = useState(0.8);
  const [globalContractility, setGlobalContractilityState] = useState(1.5);

  // Fitness Weights Configuration (Updated Defaults)
  const [foodWeight, setFoodWeightState] = useState(20.0);
  const [distanceWeight, setDistanceWeightState] = useState(20.0);

  // Scarcity Controls
  const [foodSpawnCount, setFoodSpawnCountState] = useState(50);
  const [foodSpawnRadius, setFoodSpawnRadiusState] = useState(3.5);

  // Vision Control
  const [visionRadius, setVisionRadiusState] = useState(4.0);
  const [eatRadius, setEatRadiusState] = useState(0.8);

  // Initialize
  useEffect(() => {
    const service = serviceRef.current;

    // Wire up listeners
    // Removed the High Frequency Update State trigger
    const unsubUpdate = service.subscribe('update', (pop, time) => {
        // Just update the REF. Do NOT trigger a re-render.
        // The StatsOverlay component will poll this ref via requestAnimationFrame
        const leader = service.getLeader();
        if (leader) {
            statsRef.current.fitness = leader.fitness;
            statsRef.current.foodEaten = leader.foodEaten;
            statsRef.current.distance = leader.distanceTraveled || 0;
        }
    });

    const unsubGen = service.subscribe('genComplete', (best, gen) => {
        setGeneration(gen);
        // Track History
        setFitnessHistory(prev => [...prev, best.fitness]);
    });

    const unsubNewGen = service.subscribe('newGen', (newPop) => {
        setPopulation([...newPop]);
    });

    service.initializePopulation(currentShape);
    setPopulation([...service.population]); // Initial sync

    return () => {
        cancelAnimationFrame(requestRef.current!);
        unsubUpdate();
        unsubGen();
        unsubNewGen();
    };
  }, []);

  const reset = useCallback((shape: ShapeType) => {
    setIsRunning(false);
    setIsFastForward(false);
    setCurrentShape(shape);
    serviceRef.current.initializePopulation(shape);
    setPopulation([...serviceRef.current.population]);
    setGeneration(1);
    statsRef.current = { fitness: 0, foodEaten: 0, distance: 0 };
    setFitnessHistory([]);
  }, []);

  const spawnCustom = useCallback((organism: Organism, autoStart: boolean = false) => {
      serviceRef.current.setTemplateAndReset(organism);
      setPopulation([...serviceRef.current.population]);
      setGeneration(1);
      statsRef.current = { fitness: 0, foodEaten: 0, distance: 0 };
      setFitnessHistory([]); // Clear history on new spawn
      setCurrentShape(organism.shape);

      setIsRunning(autoStart);
      setIsFastForward(false);
  }, []);

  const evolve = useCallback(() => {
    serviceRef.current.evolve();
    setPopulation([...serviceRef.current.population]); // Update React view
    setGeneration(serviceRef.current.currentGeneration);
  }, []);

  // --- PHYSICS CONTROL HANDLERS ---
  const setGlobalStiffness = useCallback((val: number) => {
      setGlobalStiffnessState(val);
      serviceRef.current.setGlobalStiffness(val);
  }, []);

  const setGlobalContractility = useCallback((val: number) => {
      setGlobalContractilityState(val);
      serviceRef.current.setGlobalContractility(val);
  }, []);

  // --- FITNESS WEIGHT HANDLERS ---
  const setFoodWeight = useCallback((val: number) => {
      setFoodWeightState(val);
      serviceRef.current.foodWeight = val;
  }, []);

  const setDistanceWeight = useCallback((val: number) => {
      setDistanceWeightState(val);
      serviceRef.current.distanceWeight = val;
  }, []);

  // --- SCARCITY HANDLERS ---
  const setFoodSpawnCount = useCallback((val: number) => {
      setFoodSpawnCountState(val);
      serviceRef.current.foodSpawnCount = val;
      serviceRef.current.updateFoodDistribution(); // Real-time update
  }, []);

  const setFoodSpawnRadius = useCallback((val: number) => {
      setFoodSpawnRadiusState(val);
      serviceRef.current.foodSpawnRadius = val;
      serviceRef.current.updateFoodDistribution(); // Real-time update
  }, []);

  // --- VISION HANDLER ---
  const setVisionRadius = useCallback((val: number) => {
      setVisionRadiusState(val);
      serviceRef.current.globalVisionRadius = val;
  }, []);

  // --- MOUTH HANDLER ---
  const setEatRadius = useCallback((val: number) => {
      setEatRadiusState(val);
      serviceRef.current.eatRadius = val;
      serviceRef.current.magnetRadius = val;
  }, []);


  // --- DATA IO ---

  const saveCreature = useCallback(() => {
    const best = serviceRef.current.getBestOrganism();
    if (!best) return;

    const json = JSON.stringify(best, null, 2);
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `creature_gen${best.generation}_${Date.now()}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }, []);

  const loadCreature = useCallback((file: File, onLoaded?: (org: Organism) => void) => {
      const reader = new FileReader();
      reader.onload = (e) => {
          try {
              const json = e.target?.result as string;
              const organism = JSON.parse(json) as Organism;

              if (!organism.nodes || !organism.muscles || !organism.neuralGenome) {
                  alert("Invalid Creature File");
                  return;
              }

              spawnCustom(organism, false);

              // Notify App
              if (onLoaded) onLoaded(organism);

          } catch (err) {
              console.error(err);
              alert("Failed to load creature file.");
          }
      };
      reader.readAsText(file);
  }, [spawnCustom]);


  // --- MAIN LOOP ---

  const toggleAutoEvolve = useCallback(() => {
      setIsFastForward(prev => !prev);
      // If we fast forward, we ensure we are running
      if (!isFastForward) setIsRunning(true); 
  }, [isFastForward]);

  const loop = useCallback(() => {
    if (!isRunning) return;

    // FAST FORWARD LOGIC:
    const iterations = isFastForward ? 8 : 1;

    for(let i=0; i<iterations; i++) {
        serviceRef.current.step(0.016);
    }

    requestRef.current = requestAnimationFrame(loop);
  }, [isRunning, isFastForward]);

  useEffect(() => {
    if (isRunning) {
      requestRef.current = requestAnimationFrame(loop);
    } else {
      cancelAnimationFrame(requestRef.current!);
    }
    return () => cancelAnimationFrame(requestRef.current!);
  }, [isRunning, loop]);

  return {
    population,
    generation,
    statsRef, // EXPOSED REF INSTEAD OF STATE
    fitnessHistory,
    isRunning,
    isAutoEvolving: isFastForward,
    currentShape,
    // Physics State
    globalStiffness,
    globalContractility,
    setGlobalStiffness,
    setGlobalContractility,
    // Fitness State
    foodWeight,
    distanceWeight,
    setFoodWeight,
    setDistanceWeight,
    // Scarcity
    foodSpawnCount,
    setFoodSpawnCount,
    foodSpawnRadius,
    setFoodSpawnRadius,
    // Vision
    visionRadius,
    setVisionRadius,
    // Mouth
    eatRadius,
    setEatRadius,
    // Actions
    setIsRunning,
    toggleAutoEvolve, 
    reset,
    evolve,
    spawnCustom,
    saveCreature,
    loadCreature
  };
}

import { Node, Muscle, Organism, SimulationConfig, CellType } from './types';
import { BrainController } from './neural/BrainController';

export class BioPhysicsEngine {
  private config: SimulationConfig;
  private readonly MAX_VELOCITY = 1.5; // HARD CAP: Max units moved per sub-step

  // SOLVER SETTINGS (Optimized)
  private readonly RELAXATION_FACTOR = 0.8; 
  private readonly ITERATIONS = 3; 

  // DAMPING SETTINGS
  private readonly BASE_MUSCLE_DAMPING = 0.08; 
  private readonly ADAPTIVE_DAMPING_FACTOR = 0.12; 
  private readonly ROTATIONAL_DRAG = 0.92; 

  // AIR RESISTANCE
  private readonly DRAG_COEFFICIENT = 0.08; 

  // --- SOLIDITY CONSTANTS ---
  private readonly NODE_RADIUS = 0.1; 
  private readonly HARD_CONTACT_LIMIT = 0.22; 

  // --- SAFETY ---
  private readonly MAX_CORRECTION = 0.5; // Max distance a muscle can pull per iteration
  private readonly WORLD_CEILING = 50.0; // If y > 50, creature has exploded. Kill it.

  // --- GRIP CONSTANTS (Reflexive System) ---
  private readonly GRIP_DRAIN_RATE = 2.5; 
  private readonly GRIP_RECHARGE_RATE = 0.05; 
  private readonly STATIC_FRICTION_THRESHOLD = 0.2; 

  constructor(config: Partial<SimulationConfig> = {}) {
    this.config = {
      gravity: -60.0, 
      friction: 0.98, 
      groundDamping: 0.5, 
      timeStep: 0.016,
      shapeMemoryStrength: 0.85, 
      globalStiffness: 0.8, 
      globalContractility: 1.5, 
      ...config
    };
  }

  public setConfig(config: Partial<SimulationConfig>) {
      this.config = { ...this.config, ...config };
  }

  public updateOrganism(organism: Organism, totalTime: number, fastMode: boolean = false): void {
    if (!organism.isAlive) return; 

    const subSteps = fastMode ? 3 : 8; 
    const subDt = this.config.timeStep / subSteps;
    const gY = this.config.gravity * subDt * subDt; // Precalc Gravity

    // OPTIMIZATION: Cache nodes array length
    const nodes = organism.nodes;
    const len = nodes.length;

    for(let s=0; s < subSteps; s++) {
        if (!organism.isAlive) break;

        // RESET STRESS in loop
        for(let i=0; i<len; i++) {
            nodes[i].currentStress = 0;
        }

        this.integrate(organism, subDt, gY);
        if (!fastMode) this.applyRotationalDrag(organism); 

        const loops = fastMode ? 2 : this.ITERATIONS;

        for (let i = 0; i < loops; i++) {
            this.resolveMuscles(organism);
            if (!fastMode && i === loops - 1) {
                this.resolveSelfCollisions(organism); 
            }
        }

        this.resolveFloor(organism);

        // --- EXPLOSION CHECK ---
        const checkNode = nodes[0];
        if (checkNode) {
            const y = checkNode.pos.y;
            if (y > this.WORLD_CEILING || !Number.isFinite(y)) {
                organism.isAlive = false;
                organism.energy = 0;
                // Reset to avoid visual stretching
                for(let i=0; i<len; i++) {
                    nodes[i].pos.x = 0; nodes[i].pos.y = 0; nodes[i].pos.z = 0;
                }
                break;
            }
        }
    }
  }

  private applyRotationalDrag(organism: Organism): void {
      const nodes = organism.nodes;
      const len = nodes.length;
      if (len === 0) return;

      let cx = 0, cz = 0;
      for (let i=0; i<len; i++) {
          cx += nodes[i].pos.x;
          cz += nodes[i].pos.z;
      }
      cx /= len;
      cz /= len;

      let angularMomentum = 0;
      let momentOfInertia = 0;

      for (let i=0; i<len; i++) {
          const n = nodes[i];
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const vx = n.pos.x - n.oldPos.x;
          const vz = n.pos.z - n.oldPos.z;

          const orbitalComponent = rx * vz - rz * vx;

          angularMomentum += orbitalComponent;
          momentOfInertia += rx * rx + rz * rz;
      }

      if (momentOfInertia < 0.001) return;

      const angularVel = angularMomentum / momentOfInertia;
      if (!Number.isFinite(angularVel)) return; 

      for (let i=0; i<len; i++) {
          const n = nodes[i];
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const dampX = -angularVel * rz * this.ROTATIONAL_DRAG;
          const dampZ =  angularVel * rx * this.ROTATIONAL_DRAG;

          n.oldPos.x += dampX;
          n.oldPos.z += dampZ;
      }
  }

  private integrate(organism: Organism, dt: number, gravityY: number): void {
    const nodes = organism.nodes;
    const friction = this.config.friction;

    // Safety cap: Max distance a node can travel in one sub-step
    const MAX_STEP = this.MAX_VELOCITY * dt; 
    const MAX_STEP_SQ = MAX_STEP * MAX_STEP;

    for (let i = 0; i < nodes.length; i++) {
      const node = nodes[i];
      if (node.isFixed) continue;

      if (node.isGripping) {
          node.oldPos.x = node.pos.x;
          node.oldPos.z = node.pos.z;
      }

      let velX = node.pos.x - node.oldPos.x;
      let velY = node.pos.y - node.oldPos.y;
      let velZ = node.pos.z - node.oldPos.z;

      // NaN Check
      if (isNaN(velX)) velX = 0;
      if (isNaN(velY)) velY = 0;
      if (isNaN(velZ)) velZ = 0;

      // Air Resistance
      const vSq = velX*velX + velY*velY + velZ*velZ;
      if (vSq > 0.000001) {
          const vLen = Math.sqrt(vSq);
          const dragFactor = 1.0 / (1.0 + this.DRAG_COEFFICIENT * vLen);
          velX *= dragFactor;
          velY *= dragFactor;
          velZ *= dragFactor;
      }

      velX *= friction;
      velY *= friction;
      velZ *= friction;

      // HARD VELOCITY CLAMP
      const finalVSq = velX*velX + velY*velY + velZ*velZ;
      if (finalVSq > MAX_STEP_SQ) {
          const scale = MAX_STEP / Math.sqrt(finalVSq);
          velX *= scale;
          velY *= scale;
          velZ *= scale;
      }

      node.oldPos.x = node.pos.x;
      node.oldPos.y = node.pos.y;
      node.oldPos.z = node.pos.z;

      node.pos.x += velX;
      node.pos.y += velY + gravityY; // Gravity is only Y here
      node.pos.z += velZ;
    }
  }

  private resolveMuscles(organism: Organism): void {
    const muscles = organism.muscles;
    const len = muscles.length;

    const ANCHOR_MULTIPLIER = 0.001; 
    const MEMORY_STRENGTH = this.config.shapeMemoryStrength || 0.8;
    const GLOBAL_STIFFNESS = this.config.globalStiffness; 

    // Lazy Load Cache Logic Moved out of hot loop ideally, but kept safe here
    if (!muscles[0]?.nodeRefA) {
         const nodeMap = new Map<string, Node>();
         for (const n of organism.nodes) nodeMap.set(n.id, n);
         for (let i=0; i<len; i++) {
             muscles[i].nodeRefA = nodeMap.get(muscles[i].nodeA);
             muscles[i].nodeRefB = nodeMap.get(muscles[i].nodeB);
         }
    }

    for (let i=0; i<len; i++) {
        const muscle = muscles[i];
        const n1 = muscle.nodeRefA;
        const n2 = muscle.nodeRefB;

        if (!n1 || !n2) continue;

        const dx = n2.pos.x - n1.pos.x;
        const dy = n2.pos.y - n1.pos.y;
        const dz = n2.pos.z - n1.pos.z;

        const distSq = dx*dx + dy*dy + dz*dz;

        if (distSq < 0.00001) continue; 
        if (distSq > 2500) continue; 

        const dist = Math.sqrt(distSq);

        // Inline target length logic
        let activeTarget = muscle.targetLength ?? muscle.baseLength;
        if (activeTarget < this.HARD_CONTACT_LIMIT) activeTarget = this.HARD_CONTACT_LIMIT;

        const stiffness = muscle.stiffness * 0.8 * GLOBAL_STIFFNESS; 
        const activeDiff = dist - activeTarget;
        const baseDiff = dist - muscle.baseLength;

        // Inline strain boost
        const strainBoost = 1.0 + ((Math.abs(baseDiff) / muscle.baseLength) * 4.0);
        const currentMemoryStrength = MEMORY_STRENGTH * strainBoost * GLOBAL_STIFFNESS;

        const activeCorrection = activeDiff * stiffness;
        const memoryCorrection = baseDiff * currentMemoryStrength;
        let totalCorrection = (activeCorrection + memoryCorrection) * this.RELAXATION_FACTOR;

        // Safety Clamp
        if (totalCorrection > this.MAX_CORRECTION) totalCorrection = this.MAX_CORRECTION;
        else if (totalCorrection < -this.MAX_CORRECTION) totalCorrection = -this.MAX_CORRECTION;

        // Inline Damping
        const rvx = (n2.pos.x - n2.oldPos.x) - (n1.pos.x - n1.oldPos.x);
        const rvy = (n2.pos.y - n2.oldPos.y) - (n1.pos.y - n1.oldPos.y);
        const rvz = (n2.pos.z - n2.oldPos.z) - (n1.pos.z - n1.oldPos.z);

        const nx = dx / dist;
        const ny = dy / dist;
        const nz = dz / dist;

        const vRelProj = rvx * nx + rvy * ny + rvz * nz;
        const dynamicDamping = this.BASE_MUSCLE_DAMPING + (Math.abs(vRelProj) * this.ADAPTIVE_DAMPING_FACTOR);

        totalCorrection += vRelProj * dynamicDamping;

        const stress = Math.abs(totalCorrection);
        n1.currentStress = (n1.currentStress || 0) + stress;
        n2.currentStress = (n2.currentStress || 0) + stress;

        let im1 = n1.isFixed ? 0 : 1 / n1.mass;
        let im2 = n2.isFixed ? 0 : 1 / n2.mass;

        if (n1.isGripping) im1 *= ANCHOR_MULTIPLIER;
        if (n2.isGripping) im2 *= ANCHOR_MULTIPLIER;

        const totalInvMass = im1 + im2;
        if (totalInvMass === 0) continue;

        const factor = totalCorrection / totalInvMass;
        const offsetX = nx * factor;
        const offsetY = ny * factor;
        const offsetZ = nz * factor;

        if (!n1.isFixed) {
            n1.pos.x += offsetX * im1;
            n1.pos.y += offsetY * im1;
            n1.pos.z += offsetZ * im1;
        }

        if (!n2.isFixed) {
            n2.pos.x -= offsetX * im2;
            n2.pos.y -= offsetY * im2;
            n2.pos.z -= offsetZ * im2;
        }
    }
  }

  private resolveSelfCollisions(organism: Organism): void {
      const nodes = organism.nodes;
      const count = nodes.length;
      const minDistance = this.HARD_CONTACT_LIMIT; 
      const minDistanceSq = minDistance * minDistance;

      for (let i = 0; i < count; i++) {
          const n1 = nodes[i];
          // Optimization: Simple spatial check could go here
          for (let j = i + 1; j < count; j++) {
              const n2 = nodes[j];

              const dx = n1.pos.x - n2.pos.x;
              const dy = n1.pos.y - n2.pos.y;
              const dz = n1.pos.z - n2.pos.z;

              // Pre-check bounding box to avoid sqrt
              if (Math.abs(dx) > minDistance || Math.abs(dy) > minDistance || Math.abs(dz) > minDistance) continue;

              const distSq = dx*dx + dy*dy + dz*dz;

              if (distSq < minDistanceSq && distSq > 0.000001) {
                  const dist = Math.sqrt(distSq);
                  const overlap = minDistance - dist;
                  const f = overlap * 0.5 / dist; // 0.2 factor removed for snappier rigidness, split 0.5

                  const fx = dx * f;
                  const fy = dy * f;
                  const fz = dz * f;

                  if (!n1.isFixed) { n1.pos.x += fx; n1.pos.y += fy; n1.pos.z += fz; }
                  if (!n2.isFixed) { n2.pos.x -= fx; n2.pos.y -= fy; n2.pos.z -= fz; }
              }
          }
      }
  }

  private resolveFloor(organism: Organism): void {
    const RADIUS = this.NODE_RADIUS;
    const KINETIC_FRICTION = 0.6; 
    const nodes = organism.nodes;

    for (let i=0; i<nodes.length; i++) {
      const node = nodes[i];
      if (node.gripStamina === undefined) node.gripStamina = 1.0;
      if (node.gripCooldown === undefined) node.gripCooldown = 0; 
      if (node.gripCooldown > 0) node.gripCooldown--;

      if (node.pos.y < RADIUS) {
        const dy = node.pos.y - node.oldPos.y;

        node.pos.y = RADIUS;

        if (dy < 0) {
             node.oldPos.y = node.pos.y + dy * this.config.groundDamping;
        }

        const isFoot = node.cellType === CellType.FOOT || (node.friction > 0.8 && !node.isHead);
        const brainWantsGrip = (node.gripSignal || 0) > 0.5;
        const canGrip = node.gripStamina > 0 && node.gripCooldown <= 0;
        const manualGrip = brainWantsGrip && canGrip;

        if (isFoot || manualGrip) {
            const vx = node.pos.x - node.oldPos.x;
            const vz = node.pos.z - node.oldPos.z;
            const vSq = vx*vx + vz*vz;

            const thresholdSq = manualGrip ? Infinity : (this.STATIC_FRICTION_THRESHOLD * this.STATIC_FRICTION_THRESHOLD);

            if (isNaN(vSq)) {
                node.isGripping = false;
                continue;
            }

            if (vSq < thresholdSq) {
                node.oldPos.x = node.pos.x;
                node.oldPos.z = node.pos.z;

                node.isGripping = true; 

                if (manualGrip) {
                    const stress = node.currentStress || 0;
                    const drain = 0.005 + (stress * this.GRIP_DRAIN_RATE);
                    node.gripStamina -= drain;
                    if (node.gripStamina <= 0) {
                        node.gripStamina = 0;
                        node.gripCooldown = 15;
                    }
                }
            } else {
                node.isGripping = false;
                // Inline friction math
                node.oldPos.x = node.pos.x - vx * KINETIC_FRICTION;
                node.oldPos.z = node.pos.z - vz * KINETIC_FRICTION;
            }
        } else {
            node.isGripping = false;
            const f = node.friction || 0.5; 
            node.oldPos.x = node.pos.x - (node.pos.x - node.oldPos.x) * f;
            node.oldPos.z = node.pos.z - (node.pos.z - node.oldPos.z) * f;
        }

      } else {
          node.isGripping = false;
          node.gripStamina += this.GRIP_RECHARGE_RATE;
          if (node.gripStamina > 1.0) node.gripStamina = 1.0;
      }
    }
  }
}

import { Organism, Node } from '../types';
import { NeuralNode } from './NeuralNode';
import { CentralPatternGenerator } from './CentralPatternGenerator';
import { VectorOps } from '../math';

// Optimization Structure
interface Synapse {
    nodeA: NeuralNode;
    nodeB: NeuralNode;
    weightIndex: number;
}

export class BrainController {
  // CHANGED: Map -> Array for fast iteration without iterator objects
  private neuralNodesList: NeuralNode[] = [];
  private neuralNodesMap: Map<string, NeuralNode> = new Map(); // Keep map only for initialization lookups

  private cpg: CentralPatternGenerator;
  private organism: Organism | null; 
  private isInitialized = false;

  private synapses: Synapse[] = []; 
  private synapseWeightsCache: Float32Array = new Float32Array(0);

  private internalTime = 0;
  private muscleRestDistances: Float32Array;

  private decisionTimer = 0;
  private readonly DECISION_INTERVAL_BASE = 0.08; 

  private previousEnergy: number = 0;
  private previousDistanceToFood: number = Infinity;
  private readonly HEBBIAN_RATE = 0.15; 

  private currentTargetId: string | null = null;
  private currentAttention: number = 0.0; 
  private readonly ATTENTION_SPAN = 6.0; 

  constructor(organism: Organism) {
    this.organism = organism;
    this.cpg = new CentralPatternGenerator(20);
    this.previousEnergy = organism.energy;

    // Initialize Neural Nodes into Array
    const nodes = organism.nodes;
    for(let i=0; i<nodes.length; i++) {
        const nn = new NeuralNode(nodes[i]);
        this.neuralNodesList.push(nn);
        this.neuralNodesMap.set(nodes[i].id, nn);
    }

    this.muscleRestDistances = new Float32Array(organism.muscles.length);

    if (organism.neuralGenome) {
        this.cpg.initialize(organism.neuralGenome.reservoirWeights);
    }
  }

  public dispose() {
      this.organism = null;
      this.neuralNodesList = [];
      this.neuralNodesMap.clear();
      this.synapses = [];
      this.synapseWeightsCache = new Float32Array(0);
      this.muscleRestDistances = new Float32Array(0);
      if (this.cpg) {
         // @ts-ignore
         this.cpg.bufferA = null;
         // @ts-ignore
         this.cpg.bufferB = null;
      }
  }

  private initializeNervousSystem() {
      if (!this.organism || this.organism.nodes.length === 0) return;

      let headNode = this.organism.headNode;
      if (!headNode) {
          headNode = this.organism.nodes[0];
          // @ts-ignore
          headNode.isHead = true; 
      }

      // 1. Build Distance Cache
      this.organism.muscles.forEach((m, i) => {
          const nA = this.organism!.nodes.find(n => n.id === m.nodeA);
          const nB = this.organism!.nodes.find(n => n.id === m.nodeB);
          if (nA && nB) {
              const midX = (nA.pos.x + nB.pos.x) / 2;
              const midY = (nA.pos.y + nB.pos.y) / 2;
              const midZ = (nA.pos.z + nB.pos.z) / 2;

              const dist = VectorOps.distance(
                  headNode!.pos, 
                  { x: midX, y: midY, z: midZ }
              );
              this.muscleRestDistances[i] = dist;
          }
      });

      // 2. Build Synapse Cache
      this.synapses = [];
      const weightCount = this.organism.neuralGenome?.synapseWeights.length || 1;
      this.synapseWeightsCache = new Float32Array(this.organism.neuralGenome.synapseWeights);

      this.organism.muscles.forEach((muscle, i) => {
          const nnA = this.neuralNodesMap.get(muscle.nodeA);
          const nnB = this.neuralNodesMap.get(muscle.nodeB);
          if (nnA && nnB) {
              this.synapses.push({
                  nodeA: nnA,
                  nodeB: nnB,
                  weightIndex: i % weightCount
              });
          }
      });

      this.organism.muscles.forEach(m => {
          m.targetLength = m.baseLength;
          m.phase = Math.random() * Math.PI * 2; 
          m.freq = 1.0; 
          m.amp = 0.0;
      });

      this.isInitialized = true;
  }

  public update(dt: number, powerScale: number = 1.0, visionRadius: number = 4.0): void {
    if (!this.organism) return;
    const genome = this.organism.neuralGenome;
    if (!genome) return;

    const safeDt = Math.min(dt, 0.1); 
    const brainDt = safeDt * (genome.internalClockSpeed || 1.0);

    if (!this.isInitialized) {
        this.initializeNervousSystem();
    }

    this.internalTime += brainDt;
    this.decisionTimer += brainDt;

    if (this.currentAttention > 0) {
        const decayPerSecond = 1.0 / this.ATTENTION_SPAN;
        this.currentAttention -= decayPerSecond * safeDt;
        if (this.currentAttention < 0) this.currentAttention = 0;
    }

    if (this.decisionTimer >= this.DECISION_INTERVAL_BASE) {
        this.think(brainDt, visionRadius);
        this.learn();
        this.decisionTimer = 0;
    }

    // --- SPINAL WAVE (Optimized Loop) ---
    const WAVE_FREQ = genome.waveFreq || 1.5; 
    const WAVE_SPEED = genome.waveSpeed || 1.0; 
    const FORCED_AMP = 0.15; 
    const MAX_DEFORMATION = 0.3; 
    const PI2 = Math.PI * 2;
    const muscles = this.organism.muscles;
    const mLen = muscles.length;

    for(let i=0; i<mLen; i++) {
        const m = muscles[i];

        m.phase += m.freq * brainDt * PI2;
        if (m.phase > PI2) m.phase -= PI2;
        const brainSignal = Math.sin(m.phase) * m.amp;

        const dist = this.muscleRestDistances[i]; 
        const nerveLag = dist * WAVE_SPEED;
        const spinalSignal = Math.sin(this.internalTime * WAVE_FREQ * PI2 - nerveLag) * FORCED_AMP;

        let totalSignal = (spinalSignal + brainSignal) * powerScale;

        if (isNaN(totalSignal)) totalSignal = 0;
        if (totalSignal > MAX_DEFORMATION) totalSignal = MAX_DEFORMATION;
        if (totalSignal < -MAX_DEFORMATION) totalSignal = -MAX_DEFORMATION;

        const desiredLength = m.baseLength * (1 + totalSignal);

        m.targetLength = (m.targetLength || m.baseLength);
        m.targetLength += (desiredLength - m.targetLength) * 0.05;
        m.currentLength = m.targetLength;
    }
  }

  private think(dt: number, visionRadius: number): void {
    if (!this.organism) return;
    const genome = this.organism.neuralGenome;

    // 1. GATHER PROPRIOCEPTION (Optimized Loop)
    let globalSensoryInput = 0;
    const nnLen = this.neuralNodesList.length;
    for (let i=0; i<nnLen; i++) {
        const nn = this.neuralNodesList[i];
        nn.sense(dt);
        globalSensoryInput += nn.inputSum;
    }

    // 2. VISION & DESIRE SYSTEM
    const head = this.organism.headNode;
    if (head) {
        const stability = Math.min(1.0, Math.max(0, (head.pos.y - 0.2))); 
        const vRadSq = visionRadius * visionRadius;

        for(const food of this.organism.visibleFood) {
            food.seen = false;
            food.targeted = false;
        }

        // A. Validate Current Lock
        let lockedFood = null;
        let lockedRealDistSq = Infinity;

        if (this.currentTargetId) {
            const found = this.organism.visibleFood.find(f => f.id === this.currentTargetId);
            if (found && !found.consumed) {
                 const dx = found.pos.x - head.pos.x;
                 const dy = found.pos.y - head.pos.y;
                 const dz = found.pos.z - head.pos.z;
                 const dSq = dx*dx + dy*dy + dz*dz;

                 if (dSq < vRadSq * 1.5) { 
                     lockedFood = found;
                     lockedRealDistSq = dSq;
                 }
            }
        }

        if (!lockedFood) {
            this.currentAttention = 0;
            this.currentTargetId = null;
        }

        let currentPerceivedCost = Infinity;
        if (lockedFood) {
            const lockFactor = this.currentAttention * 0.95;
            currentPerceivedCost = lockedRealDistSq * (1.0 - lockFactor);
        }

        let bestCandidate = lockedFood;
        let bestCost = currentPerceivedCost;
        let switched = false;

        const foods = this.organism.visibleFood;
        for (let i=0; i<foods.length; i++) {
            const food = foods[i];
            if (food.consumed) continue;
            if (lockedFood && food.id === lockedFood.id) continue;

            const dx = food.pos.x - head.pos.x;
            const dy = food.pos.y - head.pos.y;
            const dz = food.pos.z - head.pos.z;
            const distSq = dx*dx + dy*dy + dz*dz;

            if (distSq < vRadSq) {
                food.seen = true;
                const cost = distSq;
                if (cost < bestCost) {
                    bestCost = cost;
                    bestCandidate = food;
                    switched = true;
                }
            }
        }

        if (bestCandidate) {
            if (switched) {
                this.currentTargetId = bestCandidate.id;
                this.currentAttention = 1.0; 
            }

            bestCandidate.targeted = true; 

            if (stability > 0.1) {
                const dist = Math.sqrt(bestCandidate === lockedFood ? lockedRealDistSq : bestCost);
                const dx = bestCandidate.pos.x - head.pos.x;
                const dy = bestCandidate.pos.y - head.pos.y;
                const dz = bestCandidate.pos.z - head.pos.z;

                const headNeural = this.neuralNodesMap.get(head.id);
                if (headNeural && dist > 0.0001) {
                    const signalStrength = Math.max(0, 1.0 - (dist / visionRadius)) * stability;
                    headNeural.inputSum += (dx / dist) * signalStrength * 3.0; 
                    headNeural.inputSum += (dy / dist) * signalStrength * 3.0; 
                    headNeural.inputSum += (dz / dist) * signalStrength * 3.0; 
                    globalSensoryInput += signalStrength * 2.0;
                }
            }
            this.previousDistanceToFood = Math.sqrt(bestCandidate === lockedFood ? lockedRealDistSq : bestCost);
        } else {
            this.previousDistanceToFood = Infinity;
        }
    }

    globalSensoryInput /= (nnLen || 1);
    if (isNaN(globalSensoryInput)) globalSensoryInput = 0; 

    // 3. SYNAPTIC PROPAGATION (Optimized Loop)
    const sLen = this.synapses.length;
    for(let i=0; i<sLen; i++) {
        const s = this.synapses[i];
        const w = this.synapseWeightsCache[s.weightIndex]; 
        s.nodeB.inputSum += s.nodeA.activation * w;
        s.nodeA.inputSum += s.nodeB.activation * w;
    }

    for (let i=0; i<nnLen; i++) {
        this.neuralNodesList[i].updateActivation();
    }

    // 4. RESERVOIR COMPUTING
    this.cpg.tick(globalSensoryInput);

    // 5. MOTOR OUTPUT
    const mus = this.organism!.muscles;
    const len = mus.length;
    for(let i=0; i<len; i++) {
        const muscle = mus[i];
        const rawAmp = this.cpg.getSignal(i, genome.outputWeights); 
        const rawFreq = this.cpg.getSignal(i + 1, genome.outputWeights); 

        const targetAmp = Math.min(1.0, Math.abs(rawAmp)) * 0.3; 
        const targetFreq = 0.5 + ((rawFreq + 1) / 2) * 2.5;

        muscle.amp += (targetAmp - muscle.amp) * 0.1;
        muscle.freq += (targetFreq - muscle.freq) * 0.1;
    }

    // 6. SUCTION OUTPUT
    if (genome.gripWeights && genome.gripWeights.length > 0) {
        const nodes = this.organism!.nodes;
        const nLen = nodes.length;
        for(let i=0; i<nLen; i++) {
            const rawSignal = this.cpg.getSignal(i, genome.gripWeights);
            const normalized = (rawSignal + 1) / 2;
            const node = nodes[i];
            const oldGrip = node.gripSignal || 0;
            node.gripSignal = oldGrip + (normalized - oldGrip) * 0.2;
        }
    }
  }

  private learn(): void {
      if (!this.organism) return;
      const genome = this.organism.neuralGenome;
      let learningSignal = 0;

      const currentEnergy = this.organism.energy;
      const energyDelta = currentEnergy - this.previousEnergy;
      if (energyDelta > 0.5) learningSignal += 1.0;
      this.previousEnergy = currentEnergy;

      const head = this.organism.headNode;
      if (head && head.pos.y < 0.2) {
          learningSignal -= 0.5; 
      }

      if (Math.abs(learningSignal) > 0.1) {
          const len = this.synapses.length;
          for(let i=0; i<len; i++) {
              const s = this.synapses[i];
              const coActivity = s.nodeA.activation * s.nodeB.activation;

              if (coActivity > 0.1) {
                  let w = this.synapseWeightsCache[s.weightIndex]; 
                  w += this.HEBBIAN_RATE * learningSignal * coActivity;

                  if (w > 3.0) w = 3.0;
                  else if (w < -3.0) w = -3.0;

                  this.synapseWeightsCache[s.weightIndex] = w;
                  genome.synapseWeights[s.weightIndex] = w;
              }
          }
      }
  }
}

import React, { useEffect, useRef, MutableRefObject } from 'react';

interface StatsOverlayProps {
    status: 'EDITING' | 'SIMULATING';
    stats?: { fitness: number; foodEaten: number; distance: number }; // Legacy prop support
    statsRef?: MutableRefObject<{ fitness: number; foodEaten: number; distance: number }>; // New Fast Prop
    cellCount: number;
    isProcessing?: boolean;
    progress?: number;
    fitnessHistory: number[]; 
}

const FitnessGraph: React.FC<{ history: number[] }> = ({ history }) => {
    if (!history || history.length < 2) return null;

    const width = 140;
    const height = 40;
    const padding = 2;

    const maxVal = Math.max(...history, 10);
    const minVal = 0;

    const range = maxVal - minVal || 1;

    const points = history.map((val, i) => {
        const x = (i / (history.length - 1)) * (width - padding * 2) + padding;
        const normalizedY = (val - minVal) / range;
        const y = height - (normalizedY * (height - padding * 2) + padding);
        return `${x},${y}`;
    }).join(' ');

    return (
        <div className="mt-2">
            <div className="flex justify-between text-[9px] text-slate-500 font-mono mb-1">
                <span>GEN 1</span>
                <span>GEN {history.length}</span>
            </div>
            <div className="relative border border-slate-700 bg-slate-900/50 rounded overflow-hidden shadow-inner">
                <svg width={width} height={height} className="block">
                    <defs>
                        <linearGradient id="grad1" x1="0%" y1="0%" x2="0%" y2="100%">
                        <stop offset="0%" style={{stopColor:'rgb(74, 222, 128)', stopOpacity:0.5}} />
                        <stop offset="100%" style={{stopColor:'rgb(74, 222, 128)', stopOpacity:0}} />
                        </linearGradient>
                    </defs>
                    <polygon 
                        points={`0,${height} ${points} ${width},${height}`} 
                        fill="url(#grad1)" 
                    />
                    <polyline 
                        fill="none" 
                        stroke="#4ade80" 
                        strokeWidth="1.5" 
                        points={points} 
                        vectorEffect="non-scaling-stroke"
                    />
                </svg>
                <div className="absolute top-0 right-1 text-[8px] text-green-400 font-bold opacity-80">
                    {Math.round(maxVal)}
                </div>
            </div>
        </div>
    );
};

export const StatsOverlay: React.FC<StatsOverlayProps> = ({ status, stats, statsRef, cellCount, isProcessing, progress, fitnessHistory }) => {
