import React, { useState, useMemo } from 'react';
import { useEvolutionLoop } from './src/application/useEvolutionLoop';
import { BlueprintService } from './src/domain/BlueprintService';
import { ShapeType, Organism, CellType } from './src/domain/types';

// UI Components
import { UnifiedStage } from './src/infrastructure/visuals/UnifiedStage';
import { CommandBar } from './src/ui/CommandBar';
import { ToolDock } from './src/ui/ToolDock';
import { SettingsDrawer } from './src/ui/SettingsDrawer';
import { StatsOverlay } from './src/ui/StatsOverlay';

export type EditorTool = 'VIEW' | 'BUILD' | 'ERASE';

function App() {
  const {
    population,
    generation,
    statsRef, // Using Ref
    fitnessHistory, 
    isRunning,
    isAutoEvolving,
    // Physics & Env
    globalStiffness, setGlobalStiffness,
    globalContractility, setGlobalContractility,
    foodWeight, setFoodWeight,
    distanceWeight, setDistanceWeight,
    foodSpawnCount, setFoodSpawnCount,
    foodSpawnRadius, setFoodSpawnRadius,
    visionRadius, setVisionRadius,
    eatRadius, setEatRadius, // NEW
    // Actions
    setIsRunning,
    toggleAutoEvolve, 
    spawnCustom,
    saveCreature,
    loadCreature
  } = useEvolutionLoop();

  // STATE MACHINE
  const [status, setStatus] = useState<'EDITING' | 'SIMULATING'>('EDITING');
  const [showBestOnly, setShowBestOnly] = useState(false);

  // EDITOR STATE
  const blueprintService = useMemo(() => new BlueprintService(), []);
  const [blueprintCells, setBlueprintCells] = useState(blueprintService.getCells());
  const [blueprintType, setBlueprintType] = useState(ShapeType.CUBE);
  const [editorTool, setEditorTool] = useState<EditorTool>('VIEW');
  const [brushType, setBrushType] = useState<CellType>(CellType.BODY); 
  const [editingOrganism, setEditingOrganism] = useState<Organism | undefined>(undefined);

  // --- HANDLERS ---

  const handlePlay = () => {
      // 1. Generate Organism from Blueprint
      // Pass 'editingOrganism' to graft the brain if it exists
      const organism = blueprintService.generateOrganism('prototype', editingOrganism);

      // 2. Inject into Engine and Start
      spawnCustom(organism, true); // true = autoStart

      // 3. Switch State
      setStatus('SIMULATING');
  };

  const handleStop = () => {
      setIsRunning(false);
      // If Auto Evolving (Fast Forward), stop it
      if (isAutoEvolving) toggleAutoEvolve();

      setStatus('EDITING');
  };

  // --- BLUEPRINT ACTIONS ---

  const handleLoad = (file: File) => {
      loadCreature(file, (org) => {
          blueprintService.importOrganism(org);
          setBlueprintCells(blueprintService.getCells());
          setBlueprintType(org.shape || ShapeType.CUBE);
          setEditingOrganism(org);
          setStatus('EDITING');
      });
  };

  const handleCellClick = (x: number, y: number, z: number, isRight: boolean) => {
      if (isRight) {
          blueprintService.setCell(x, y, z, null); // Erase
      } else {
          blueprintService.setCell(x, y, z, brushType); // Build with active brush
      }
      setBlueprintCells(blueprintService.getCells());
  };

  const handleGenerate = (type: string) => {
      setEditingOrganism(undefined); // Fresh brain
      if (type === 'small') blueprintService.generateSmallCritter();
      if (type === 'large') blueprintService.generateLargeBeast();
      if (type === 'worm') blueprintService.applyWorm(8);
      if (type === 'mirror') blueprintService.applyMirrorX();

      setBlueprintCells(blueprintService.getCells());
  };

  const handleClear = () => {
      blueprintService.clear();
      setBlueprintCells([]);
      setEditingOrganism(undefined);
  };

  const handleSetShape = (t: ShapeType) => {
      setBlueprintType(t);
      blueprintService.setType(t);
      setBlueprintCells([...blueprintService.getCells()]);
  };

  return (
    <div className="relative w-full h-full overflow-hidden bg-slate-900 select-none">

      {/* 3D STAGE */}
      <UnifiedStage 
          status={status}
          population={population}
          visionRadius={visionRadius}
          eatRadius={eatRadius} // PASSED PROP
          showBestOnly={showBestOnly}
          // Edit Props
          blueprintCells={blueprintCells}
          blueprintType={blueprintType}
          editorTool={editorTool}
          brushType={brushType}
          onCellClick={handleCellClick}
      />

      {/* --- HUD OVERLAYS --- */}

      <StatsOverlay 
          status={status}
          statsRef={statsRef}
          cellCount={blueprintCells.length}
          isProcessing={false} 
          progress={0}
          fitnessHistory={fitnessHistory}
      />

      <ToolDock 
          status={status}
          editorTool={editorTool}
          setEditorTool={setEditorTool}
          brushType={brushType}
          setBrushType={setBrushType}
          currentShape={blueprintType}
          setShape={handleSetShape}
          onClear={handleClear}
          onGenerate={handleGenerate}
      />

      <CommandBar 
          status={status}
          isRunning={isRunning}
          isAutoEvolving={isAutoEvolving}
          generation={generation}
          onPlay={handlePlay}
          onStop={handleStop}
          onTogglePause={() => setIsRunning(!isRunning)}
          onToggleAuto={toggleAutoEvolve}
      />

      <SettingsDrawer 
          globalStiffness={globalStiffness} setGlobalStiffness={setGlobalStiffness}
          globalContractility={globalContractility} setGlobalContractility={setGlobalContractility}
          foodWeight={foodWeight} setFoodWeight={setFoodWeight}
          distanceWeight={distanceWeight} setDistanceWeight={setDistanceWeight}
          foodSpawnCount={foodSpawnCount} setFoodSpawnCount={setFoodSpawnCount}
          foodSpawnRadius={foodSpawnRadius} setFoodSpawnRadius={setFoodSpawnRadius}
          visionRadius={visionRadius} setVisionRadius={setVisionRadius}
          eatRadius={eatRadius} setEatRadius={setEatRadius} 
          showBestOnly={showBestOnly}
          onToggleBestOnly={() => setShowBestOnly(!showBestOnly)}
          onSave={saveCreature}
          onLoad={handleLoad}
      />

    </div>
  );
}

export default App;

import { Node, Muscle, Organism, SimulationConfig, CellType } from './types';
import { BrainController } from './neural/BrainController';

export class BioPhysicsEngine {
  private config: SimulationConfig;
  private readonly MAX_VELOCITY = 1.5; // HARD CAP: Max units moved per sub-step

  // SOLVER SETTINGS (Optimized)
  private readonly RELAXATION_FACTOR = 0.8; 
  private readonly ITERATIONS = 3; 

  // DAMPING SETTINGS
  private readonly BASE_MUSCLE_DAMPING = 0.08; 
  private readonly ADAPTIVE_DAMPING_FACTOR = 0.12; 
  private readonly ROTATIONAL_DRAG = 0.92; 

  // AIR RESISTANCE
  private readonly DRAG_COEFFICIENT = 0.08; 

  // --- SOLIDITY CONSTANTS ---
  private readonly NODE_RADIUS = 0.1; 
  private readonly HARD_CONTACT_LIMIT = 0.22; 

  // --- SAFETY ---
  private readonly MAX_CORRECTION = 0.5; // Max distance a muscle can pull per iteration
  private readonly WORLD_CEILING = 50.0; // If y > 50, creature has exploded. Kill it.

  // --- GRIP CONSTANTS (Reflexive System) ---
  private readonly GRIP_DRAIN_RATE = 2.5; 
  private readonly GRIP_RECHARGE_RATE = 0.05; 
  private readonly STATIC_FRICTION_THRESHOLD = 0.2; 

  constructor(config: Partial<SimulationConfig> = {}) {
    this.config = {
      gravity: -65.0, // Slightly increased from -60.0 to feel more weighted
      friction: 0.98, 
      groundDamping: 0.5, 
      timeStep: 0.016,
      shapeMemoryStrength: 0.75, // Reduced from 0.85 to reduce "rigid truss" behavior
      globalStiffness: 0.75, // Reduced from 0.8 to allow slight sagging under load
      globalContractility: 1.5, 
      ...config
    };
  }

  public setConfig(config: Partial<SimulationConfig>) {
      this.config = { ...this.config, ...config };
  }

  public updateOrganism(organism: Organism, totalTime: number, fastMode: boolean = false): void {
    if (!organism.isAlive) return; 

    const subSteps = fastMode ? 3 : 8; 
    const subDt = this.config.timeStep / subSteps;
    const gY = this.config.gravity * subDt * subDt; // Precalc Gravity

    // OPTIMIZATION: Cache nodes array length
    const nodes = organism.nodes;
    const len = nodes.length;

    for(let s=0; s < subSteps; s++) {
        if (!organism.isAlive) break;

        // RESET STRESS in loop
        for(let i=0; i<len; i++) {
            nodes[i].currentStress = 0;
        }

        this.integrate(organism, subDt, gY);
        if (!fastMode) this.applyRotationalDrag(organism); 

        const loops = fastMode ? 2 : this.ITERATIONS;

        for (let i = 0; i < loops; i++) {
            this.resolveMuscles(organism);
            if (!fastMode && i === loops - 1) {
                this.resolveSelfCollisions(organism); 
            }
        }

        this.resolveFloor(organism);

        // --- EXPLOSION CHECK ---
        const checkNode = nodes[0];
        if (checkNode) {
            const y = checkNode.pos.y;
            if (y > this.WORLD_CEILING || !Number.isFinite(y)) {
                organism.isAlive = false;
                organism.energy = 0;
                // Reset to avoid visual stretching
                for(let i=0; i<len; i++) {
                    nodes[i].pos.x = 0; nodes[i].pos.y = 0; nodes[i].pos.z = 0;
                }
                break;
            }
        }
    }
  }

  private applyRotationalDrag(organism: Organism): void {
      const nodes = organism.nodes;
      const len = nodes.length;
      if (len === 0) return;

      let cx = 0, cz = 0;
      for (let i=0; i<len; i++) {
          cx += nodes[i].pos.x;
          cz += nodes[i].pos.z;
      }
      cx /= len;
      cz /= len;

      let angularMomentum = 0;
      let momentOfInertia = 0;

      for (let i=0; i<len; i++) {
          const n = nodes[i];
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const vx = n.pos.x - n.oldPos.x;
          const vz = n.pos.z - n.oldPos.z;

          const orbitalComponent = rx * vz - rz * vx;

          angularMomentum += orbitalComponent;
          momentOfInertia += rx * rx + rz * rz;
      }

      if (momentOfInertia < 0.001) return;

      const angularVel = angularMomentum / momentOfInertia;
      if (!Number.isFinite(angularVel)) return; 

      for (let i=0; i<len; i++) {
          const n = nodes[i];
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const dampX = -angularVel * rz * this.ROTATIONAL_DRAG;
          const dampZ =  angularVel * rx * this.ROTATIONAL_DRAG;

          n.oldPos.x += dampX;
          n.oldPos.z += dampZ;
      }
  }

  private integrate(organism: Organism, dt: number, gravityY: number): void {
    const nodes = organism.nodes;
    const friction = this.config.friction;

    // Safety cap: Max distance a node can travel in one sub-step
    const MAX_STEP = this.MAX_VELOCITY * dt; 
    const MAX_STEP_SQ = MAX_STEP * MAX_STEP;

    for (let i = 0; i < nodes.length; i++) {
      const node = nodes[i];
      if (node.isFixed) continue;

      if (node.isGripping) {
          node.oldPos.x = node.pos.x;
          node.oldPos.z = node.pos.z;
      }

      let velX = node.pos.x - node.oldPos.x;
      let velY = node.pos.y - node.oldPos.y;
      let velZ = node.pos.z - node.oldPos.z;

      // NaN Check
      if (isNaN(velX)) velX = 0;
      if (isNaN(velY)) velY = 0;
      if (isNaN(velZ)) velZ = 0;

      // Air Resistance
      const vSq = velX*velX + velY*velY + velZ*velZ;
      if (vSq > 0.000001) {
          const vLen = Math.sqrt(vSq);
          const dragFactor = 1.0 / (1.0 + this.DRAG_COEFFICIENT * vLen);
          velX *= dragFactor;
          velY *= dragFactor;
          velZ *= dragFactor;
      }

      velX *= friction;
      velY *= friction;
      velZ *= friction;

      // HARD VELOCITY CLAMP
      const finalVSq = velX*velX + velY*velY + velZ*velZ;
      if (finalVSq > MAX_STEP_SQ) {
          const scale = MAX_STEP / Math.sqrt(finalVSq);
          velX *= scale;
          velY *= scale;
          velZ *= scale;
      }

      node.oldPos.x = node.pos.x;
      node.oldPos.y = node.pos.y;
      node.oldPos.z = node.pos.z;

      node.pos.x += velX;
      node.pos.y += velY + gravityY; // Gravity is only Y here
      node.pos.z += velZ;
    }
  }

  private resolveMuscles(organism: Organism): void {
    const muscles = organism.muscles;
    const len = muscles.length;

    const ANCHOR_MULTIPLIER = 0.001; 
    const MEMORY_STRENGTH = this.config.shapeMemoryStrength || 0.8;
    const GLOBAL_STIFFNESS = this.config.globalStiffness; 

    // Lazy Load Cache Logic Moved out of hot loop ideally, but kept safe here
    if (!muscles[0]?.nodeRefA) {
         const nodeMap = new Map<string, Node>();
         for (const n of organism.nodes) nodeMap.set(n.id, n);
         for (let i=0; i<len; i++) {
             muscles[i].nodeRefA = nodeMap.get(muscles[i].nodeA);
             muscles[i].nodeRefB = nodeMap.get(muscles[i].nodeB);
         }
    }

    for (let i=0; i<len; i++) {
        const muscle = muscles[i];
        const n1 = muscle.nodeRefA;
        const n2 = muscle.nodeRefB;

        if (!n1 || !n2) continue;

        const dx = n2.pos.x - n1.pos.x;
        const dy = n2.pos.y - n1.pos.y;
        const dz = n2.pos.z - n1.pos.z;

        const distSq = dx*dx + dy*dy + dz*dz;

        if (distSq < 0.00001) continue; 
        if (distSq > 2500) continue; 

        const dist = Math.sqrt(distSq);

        // Inline target length logic
        let activeTarget = muscle.targetLength ?? muscle.baseLength;
        if (activeTarget < this.HARD_CONTACT_LIMIT) activeTarget = this.HARD_CONTACT_LIMIT;

        const stiffness = muscle.stiffness * 0.8 * GLOBAL_STIFFNESS; 
        const activeDiff = dist - activeTarget;
        const baseDiff = dist - muscle.baseLength;

        // Inline strain boost
        const strainBoost = 1.0 + ((Math.abs(baseDiff) / muscle.baseLength) * 4.0);
        const currentMemoryStrength = MEMORY_STRENGTH * strainBoost * GLOBAL_STIFFNESS;

        const activeCorrection = activeDiff * stiffness;
        const memoryCorrection = baseDiff * currentMemoryStrength;
        let totalCorrection = (activeCorrection + memoryCorrection) * this.RELAXATION_FACTOR;

        // Safety Clamp
        if (totalCorrection > this.MAX_CORRECTION) totalCorrection = this.MAX_CORRECTION;
        else if (totalCorrection < -this.MAX_CORRECTION) totalCorrection = -this.MAX_CORRECTION;

        // Inline Damping
        const rvx = (n2.pos.x - n2.oldPos.x) - (n1.pos.x - n1.oldPos.x);
        const rvy = (n2.pos.y - n2.oldPos.y) - (n1.pos.y - n1.oldPos.y);
        const rvz = (n2.pos.z - n2.oldPos.z) - (n1.pos.z - n1.oldPos.z);

        const nx = dx / dist;
        const ny = dy / dist;
        const nz = dz / dist;

        const vRelProj = rvx * nx + rvy * ny + rvz * nz;
        const dynamicDamping = this.BASE_MUSCLE_DAMPING + (Math.abs(vRelProj) * this.ADAPTIVE_DAMPING_FACTOR);

        totalCorrection += vRelProj * dynamicDamping;

        const stress = Math.abs(totalCorrection);
        n1.currentStress = (n1.currentStress || 0) + stress;
        n2.currentStress = (n2.currentStress || 0) + stress;

        let im1 = n1.isFixed ? 0 : 1 / n1.mass;
        let im2 = n2.isFixed ? 0 : 1 / n2.mass;

        if (n1.isGripping) im1 *= ANCHOR_MULTIPLIER;
        if (n2.isGripping) im2 *= ANCHOR_MULTIPLIER;

        const totalInvMass = im1 + im2;
        if (totalInvMass === 0) continue;

        const factor = totalCorrection / totalInvMass;
        const offsetX = nx * factor;
        const offsetY = ny * factor;
        const offsetZ = nz * factor;

        if (!n1.isFixed) {
            n1.pos.x += offsetX * im1;
            n1.pos.y += offsetY * im1;
            n1.pos.z += offsetZ * im1;
        }

        if (!n2.isFixed) {
            n2.pos.x -= offsetX * im2;
            n2.pos.y -= offsetY * im2;
            n2.pos.z -= offsetZ * im2;
        }
    }
  }

  private resolveSelfCollisions(organism: Organism): void {
      const nodes = organism.nodes;
      const count = nodes.length;
      const minDistance = this.HARD_CONTACT_LIMIT; 
      const minDistanceSq = minDistance * minDistance;

      for (let i = 0; i < count; i++) {
          const n1 = nodes[i];
          // Optimization: Simple spatial check could go here
          for (let j = i + 1; j < count; j++) {
              const n2 = nodes[j];

              const dx = n1.pos.x - n2.pos.x;
              const dy = n1.pos.y - n2.pos.y;
              const dz = n1.pos.z - n2.pos.z;

              // Pre-check bounding box to avoid sqrt
              if (Math.abs(dx) > minDistance || Math.abs(dy) > minDistance || Math.abs(dz) > minDistance) continue;

              const distSq = dx*dx + dy*dy + dz*dz;

              if (distSq < minDistanceSq && distSq > 0.000001) {
                  const dist = Math.sqrt(distSq);
                  const overlap = minDistance - dist;
                  const f = overlap * 0.5 / dist; // 0.2 factor removed for snappier rigidness, split 0.5

                  const fx = dx * f;
                  const fy = dy * f;
                  const fz = dz * f;

                  if (!n1.isFixed) { n1.pos.x += fx; n1.pos.y += fy; n1.pos.z += fz; }
                  if (!n2.isFixed) { n2.pos.x -= fx; n2.pos.y -= fy; n2.pos.z -= fz; }
              }
          }
      }
  }

  private resolveFloor(organism: Organism): void {
    const RADIUS = this.NODE_RADIUS;
    const KINETIC_FRICTION = 0.6; 
    const nodes = organism.nodes;

    for (let i=0; i<nodes.length; i++) {
      const node = nodes[i];
      if (node.gripStamina === undefined) node.gripStamina = 1.0;
      if (node.gripCooldown === undefined) node.gripCooldown = 0; 
      if (node.gripCooldown > 0) node.gripCooldown--;

      if (node.pos.y < RADIUS) {
        const dy = node.pos.y - node.oldPos.y;

        node.pos.y = RADIUS;

        if (dy < 0) {
             node.oldPos.y = node.pos.y + dy * this.config.groundDamping;
        }

        const isFoot = node.cellType === CellType.FOOT || (node.friction > 0.8 && !node.isHead);
        const brainWantsGrip = (node.gripSignal || 0) > 0.5;
        const canGrip = node.gripStamina > 0 && node.gripCooldown <= 0;
        const manualGrip = brainWantsGrip && canGrip;

        if (isFoot || manualGrip) {
            const vx = node.pos.x - node.oldPos.x;
            const vz = node.pos.z - node.oldPos.z;
            const vSq = vx*vx + vz*vz;

            const thresholdSq = manualGrip ? Infinity : (this.STATIC_FRICTION_THRESHOLD * this.STATIC_FRICTION_THRESHOLD);

            if (isNaN(vSq)) {
                node.isGripping = false;
                continue;
            }

            if (vSq < thresholdSq) {
                node.oldPos.x = node.pos.x;
                node.oldPos.z = node.pos.z;

                node.isGripping = true; 

                if (manualGrip) {
                    const stress = node.currentStress || 0;
                    const drain = 0.005 + (stress * this.GRIP_DRAIN_RATE);
                    node.gripStamina -= drain;
                    if (node.gripStamina <= 0) {
                        node.gripStamina = 0;
                        node.gripCooldown = 15;
                    }
                }
            } else {
                node.isGripping = false;
                // Inline friction math
                node.oldPos.x = node.pos.x - vx * KINETIC_FRICTION;
                node.oldPos.z = node.pos.z - vz * KINETIC_FRICTION;
            }
        } else {
            node.isGripping = false;
            const f = node.friction || 0.5; 
            node.oldPos.x = node.pos.x - (node.pos.x - node.oldPos.x) * f;
            node.oldPos.z = node.pos.z - (node.pos.z - node.oldPos.z) * f;
        }

      } else {
          node.isGripping = false;
          node.gripStamina += this.GRIP_RECHARGE_RATE;
          if (node.gripStamina > 1.0) node.gripStamina = 1.0;
      }
    }
  }
}

import { Organism, ShapeType, Node, Muscle, NeuralGenome } from './types';
import { VectorOps } from './math';
import { GeneticOperator } from './genetics/GeneticOperator';

export class ShapeFactory {

  static create(type: ShapeType, id: string): Organism {
    let nodes: Node[] = [];
    let muscles: Muscle[] = [];

    if (type === ShapeType.WORM) {
        ({ nodes, muscles } = this.createWorm(4));
    } else {
        // Default to Cube
        ({ nodes, muscles } = this.createCube());
    }

    // Initialize Neural Genome
    const operator = new GeneticOperator();
    const genome = operator.createRandomGenome(muscles.length, nodes.length);

    // Optimized loop instead of forEach
    for(let i=0; i<muscles.length; i++) {
        muscles[i].dnaIndex = i;
    }

    // Identify Head (Furthest Forward, then Highest Up)
    let maxZ = -Infinity;
    for(let i=0; i<nodes.length; i++) {
        if (nodes[i].pos.z > maxZ) maxZ = nodes[i].pos.z;
    }

    let candidates: Node[] = [];
    for(let i=0; i<nodes.length; i++) {
        if (Math.abs(nodes[i].pos.z - maxZ) < 0.1) candidates.push(nodes[i]);
    }

    let headNode: Node | undefined = undefined;
    let maxY = -Infinity;
    for(let i=0; i<candidates.length; i++) {
        if (candidates[i].pos.y > maxY) {
            maxY = candidates[i].pos.y;
            headNode = candidates[i];
        }
    }

    if (headNode) {
        // @ts-ignore
        headNode.isHead = true;
    }

    const initialHeadPos = headNode ? { ...headNode.pos } : { x: 0, y: 0, z: 0 };

    return {
      id,
      shape: type, // Store shape type for editor consistency
      nodes,
      muscles,
      neuralGenome: genome,
      fitness: 0,
      generation: 1,
      // Metabolism Defaults
      energy: 100,
      maxEnergy: 100,
      hungerTime: 0,
      isAlive: true,
      foodEaten: 0,
      visibleFood: [],
      // Distance Metrics (Replaces Posture)
      initialHeadPos,
      distanceTraveled: 0,
      headNode // OPTIMIZATION
    };
  }

  // HELPER: Factory for optimized Node creation
  // Initializes all fields to ensure stable V8 Hidden Class
  private static createNode(id: string, x: number, y: number, z: number, mass: number, friction: number): Node {
      return {
          id,
          pos: { x, y, z },
          oldPos: { x, y, z },
          mass,
          friction,
          // Explicitly init optional fields to avoid de-opt
          isHead: false,
          isFixed: false,
          isGripping: false,
          gripSignal: 0,
          gripStamina: 1.0, // Start full
          currentStress: 0,
          activation: 0,
          originalGridCoord: undefined,
          gripCooldown: 0 // Init for stability
      };
  }

  private static createCube() {
    const nodes: Node[] = [];
    const size = 1.0;
    const startY = 0.5;
    const f = 0.95; 

    for(let x=0; x<=1; x++) {
      for(let y=0; y<=1; y++) {
        for(let z=0; z<=1; z++) {
          const px = (x - 0.5) * size;
          const py = startY + y * size;
          const pz = (z - 0.5) * size;

          // Mass distribution: Top (y>0) is slightly heavier (5.0) than feet (4.0)
          // This makes the creature top-heavy and prevents easy pivoting.
          const mass = y > 0 ? 5.0 : 4.0;

          nodes.push(this.createNode(`n${x}${y}${z}`, px, py, pz, mass, f));
        }
      }
    }
    const muscles = this.connectDistanceThreshold(nodes, size * 1.8);
    return { nodes, muscles };
  }

  private static createWorm(segments: number) {
    const nodes: Node[] = [];
    const size = 1.0;
    const bellyFriction = 0.5; 
    const footFriction = 0.98; 
    const m = 4.0; 
    const mTop = 5.0; // Heavier top spine

    for (let i = 0; i < segments; i++) {
        const offset = i * size;
        nodes.push(
            this.createNode(`n${i}_a`, -0.5, 0, offset, m, footFriction),
            this.createNode(`n${i}_b`, 0.5, 0, offset, m, footFriction),
            this.createNode(`n${i}_top`, 0, 1, offset + 0.5, mTop, bellyFriction)
        );
    }
    return { nodes, muscles: this.connectDistanceThreshold(nodes, size * 1.5) };
  }

    private static connectDistanceThreshold(nodes: Node[], threshold: number): Muscle[] {
      const muscles: Muscle[] = [];
      let mCount = 0;
      for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
          const dist = VectorOps.distance(nodes[i].pos, nodes[j].pos);
          if (dist <= threshold) {
            muscles.push({
              id: `m${mCount++}`,
              nodeA: nodes[i].id,
              nodeB: nodes[j].id,
              baseLength: dist,
              stiffness: 1.0,
              dnaIndex: 0,
              phase: Math.random() * Math.PI * 2,
              freq: 1.0,
              amp: 0.0,
              currentLength: dist,
              targetLength: dist,
              nodeRefA: undefined,
              nodeRefB: undefined
            });
          }
        }
      }
      return muscles;
    }
}

import { ShapeType, Organism, Node, Muscle, NeuralGenome, GridCoord, CellType, BlueprintCell } from './types';
import { VectorOps } from './math';
import { LatticeFactory, ILatticeStrategy } from './lattice/LatticeStrategy';
import { GeneticOperator } from './genetics/GeneticOperator';

export class BlueprintService {
  private cells: Map<string, CellType> = new Map();
  private type: ShapeType = ShapeType.CUBE;
  private readonly GRID_SIZE = 10; 
  private geneticOperator: GeneticOperator;

  constructor() {
    this.geneticOperator = new GeneticOperator();
    this.clear();
  }

  public setType(t: ShapeType) {
    this.type = t;
  }

  public clear() {
    this.cells.clear();
  }

  public getCells(): BlueprintCell[] {
    const res: BlueprintCell[] = [];
    this.cells.forEach((type, key) => {
        const [x, y, z] = key.split(',').map(Number);
        res.push({ x, y, z, type });
    });
    return res;
  }

  public setCell(x: number, y: number, z: number, type: CellType | null) {
    const key = `${Math.round(x)},${Math.round(y)},${Math.round(z)}`;
    if (type) {
        // If we are placing a HEAD, remove any existing HEAD to ensure only one leader
        if (type === CellType.HEAD) {
            this.cells.forEach((val, k) => {
                if (val === CellType.HEAD) this.cells.set(k, CellType.BODY);
            });
        }
        this.cells.set(key, type);
    } else {
        this.cells.delete(key);
    }
  }

  public hasCell(x: number, y: number, z: number): boolean {
      return this.cells.has(`${x},${y},${z}`);
  }

  // --- HEURISTICS ---

  public generateSmallCritter() {
      this.clear();
      const rng = () => Math.random();
      const length = 4 + Math.floor(rng() * 3);
      const wideStance = rng() > 0.4;
      const legX = wideStance ? 2 : 1;

      // Body (Slippery)
      for(let z=0; z<length; z++) this.setCell(0, 1, z, CellType.BODY);

      const headZ = length - 1;
      this.setCell(0, 2, headZ, CellType.HEAD); // Explicit Head

      // Decorative Spine
      if (rng() > 0.5) this.setCell(0, 3, headZ, CellType.BODY);

      const frontLegZ = Math.max(0, headZ - 1);
      const backLegZ = 0;

      const addLeg = (z: number) => {
          this.setCell(legX, 0, z, CellType.FOOT); // Feet
          this.setCell(1, 1, z, CellType.BODY);
          if (legX === 2) this.setCell(1, 0, z, CellType.FOOT);
      };

      addLeg(backLegZ);
      addLeg(frontLegZ);

      for(let z=1; z < length - 1; z++) {
           if (rng() > 0.6) this.setCell(1, 1, z, CellType.BODY);
      }
      this.applyMirrorX();
  }

  public generateLargeBeast() {
    this.clear();
    const rng = () => Math.random();
    const range = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;

    const bodyLength = range(5, 8);
    const bodyHeight = range(2, 4); 
    const zOffset = -Math.floor(bodyLength / 2);

    for (let z = 0; z < bodyLength; z++) {
        const absZ = z + zOffset;
        this.setCell(0, bodyHeight, absZ, CellType.BODY);
        if (rng() > 0.4) this.setCell(0, bodyHeight + 1, absZ, CellType.BODY);
        if (rng() > 0.4 && bodyHeight > 1) this.setCell(0, bodyHeight - 1, absZ, CellType.BODY);
    }

    const numLegPairs = range(2, 4); 
    const legSpacing = Math.floor(bodyLength / numLegPairs);

    for (let i = 0; i < numLegPairs; i++) {
        const zIndex = (i * legSpacing) + Math.floor(legSpacing/2);
        if (zIndex >= bodyLength) continue;

        const startZ = zIndex + zOffset;
        const startY = bodyHeight;
        const startX = 0;
        let cx = startX;
        let cy = startY;
        let cz = startZ;

        cx++;
        this.setCell(cx, cy, cz, CellType.BODY);

        let safety = 0;
        while (cy > 0 && safety++ < 10) {
            const moveDown = rng() > 0.3; 
            if (moveDown) cy--;
            else {
                if (rng() > 0.4) cx++; 
                else cz += (rng() > 0.5 ? 1 : -1); 
            }
            // If on ground, it's a foot
            const type = cy === 0 ? CellType.FOOT : CellType.BODY;
            this.setCell(cx, cy, cz, type);
        }

        if (cy === 0) {
            this.setCell(cx + 1, 0, cz, CellType.FOOT);
            this.setCell(cx - 1, 0, cz, CellType.FOOT);
        }
    }

    const headZ = (bodyLength - 1) + zOffset + 1;
    this.setCell(0, bodyHeight + 1, headZ, CellType.HEAD);
    this.setCell(0, bodyHeight, headZ, CellType.BODY);
    this.setCell(0, bodyHeight - 1, headZ, CellType.BODY);

    this.applyMirrorX();
  }

  public applyWorm(length: number) {
      let curr = { x: 0, y: 0, z: 0 };
      this.setCell(0, 0, 0, CellType.FOOT); // Tail anchor

      for(let i=0; i<length; i++) {
          const axis = Math.floor(Math.random() * 3);
          const dir = Math.random() > 0.5 ? 1 : -1;

          if (axis === 0) curr.x += dir;
          if (axis === 1) curr.y += dir;
          if (axis === 2) curr.z += dir;
          if (Math.abs(curr.x) > 4) curr.x -= dir;
          if (Math.abs(curr.y) > 4) curr.y -= dir;
          if (Math.abs(curr.z) > 4) curr.z -= dir;

          const type = i === length - 1 ? CellType.HEAD : (curr.y === 0 ? CellType.FOOT : CellType.BODY);
          this.setCell(curr.x, curr.y, curr.z, type);
      }
  }

  public applyMirrorX() {
      const newCells = new Map<string, CellType>();
      this.cells.forEach((type, key) => {
          const [x, y, z] = key.split(',').map(Number);
          newCells.set(key, type);

          const mx = -x;
          newCells.set(`${mx},${y},${z}`, type);
      });
      this.cells = newCells;
  }

  public importOrganism(org: Organism) {
      this.clear();
      this.type = org.shape || ShapeType.CUBE; 

      let needsVoxelization = false;
      for (const node of org.nodes) {
          if (node.originalGridCoord) {
              // Use stored type if available, otherwise fallback
              const type = node.cellType || (node.isHead ? CellType.HEAD : (node.friction > 0.6 ? CellType.FOOT : CellType.BODY));
              this.setCell(node.originalGridCoord.x, node.originalGridCoord.y, node.originalGridCoord.z, type);
          } else {
              needsVoxelization = true;
          }
      }

      // Fallback: If no metadata (legacy creature), try to voxelize based on position
      if (needsVoxelization) {
          org.nodes.forEach(n => {
             // Simple quantization fallback
             const x = Math.round(n.pos.x);
             const y = Math.round(n.pos.y);
             const z = Math.round(n.pos.z);
             const type = n.isHead ? CellType.HEAD : (y < 0.2 ? CellType.FOOT : CellType.BODY);
             this.setCell(x, y, z, type);
          });
      }
  }

  // --- EXPORT TO PHYSICS WITH BRAIN GRAFTING ---

  public generateOrganism(id: string, source?: Organism): Organism {
      const strategy: ILatticeStrategy = LatticeFactory.getStrategy(this.type);

      const nodes: Node[] = [];
      const muscles: Muscle[] = [];
      const coordToNodeId = new Map<string, string>();
      const createdMuscles = new Set<string>();

      const activeCells = this.getCells();
      if (activeCells.length === 0) {
          // Default start if empty
          this.setCell(0,0,0, CellType.FOOT);
          this.setCell(0,1,0, CellType.HEAD);
          activeCells.push({x:0,y:0,z:0, type: CellType.FOOT}, {x:0,y:1,z:0, type: CellType.HEAD});
      }

      // --- HEIGHT NORMALIZATION ---
      // Ensure the creature sits on the floor regardless of editor position
      let minY = Infinity;
      for(let i=0; i<activeCells.length; i++) {
          const w = strategy.gridToWorld(activeCells[i], 0.8);
          if(w.y < minY) minY = w.y;
      }
      const heightOffset = -minY + 0.1; // Slight float

      const scale = 0.8; 

      // 1. Generate Nodes
      activeCells.forEach((c) => {
          const nodeId = `n_${c.x}_${c.y}_${c.z}`;
          coordToNodeId.set(`${c.x},${c.y},${c.z}`, nodeId);

          const worldPos = strategy.gridToWorld(c, scale);
          worldPos.y += heightOffset;

          // SPECIALIZED BRICK PROPERTIES
          let mass = 1.0;
          let friction = 0.4; // Default slippery body
          let isHead = false;

          if (c.type === CellType.HEAD) {
              isHead = true;
              mass = 1.0; // Standardize head mass
              friction = 0.4;
          } else if (c.type === CellType.FOOT) {
              mass = 1.2; // Anchors are decently heavy
              friction = 0.9; // Sticky
          } else {
              // BODY
              mass = 1.4; // Top Heavy to discourage pivots (heavier than feet)
              friction = 0.1; // Very slippery to allow sliding
          }

          nodes.push({
              id: nodeId,
              pos: worldPos,
              oldPos: VectorOps.copy(worldPos),
              mass,
              friction,
              isHead,
              originalGridCoord: { x: c.x, y: c.y, z: c.z },
              cellType: c.type // Persist for restoration
          });
      });

      // 2. Identify Head (Fallback logic if user placed no head)
      let headNode = nodes.find(n => n.isHead);

      if (!headNode) {
          // Heuristic Fallback
          let maxZ = -Infinity;
          for(let i=0; i<nodes.length; i++) { if (nodes[i].pos.z > maxZ) maxZ = nodes[i].pos.z; }

          let candidates: Node[] = [];
          for(let i=0; i<nodes.length; i++) { if (Math.abs(nodes[i].pos.z - maxZ) < 0.1) candidates.push(nodes[i]); }

          let maxY = -Infinity;
          for(let i=0; i<candidates.length; i++) { if (candidates[i].pos.y > maxY) maxY = candidates[i].pos.y; }

          headNode = candidates.find(n => Math.abs(n.pos.y - maxY) < 0.1);

          if (headNode) {
              // @ts-ignore
              headNode.isHead = true;
          }
      }

      // Init Head Pos
      const initialHeadPos = headNode ? { ...headNode.pos } : { x: 0, y: 0, z: 0 };

      // 3. Connect Muscles using Strategy
      const addMuscle = (n1: string, n2: string, stiffness: number = 0.8) => {
          const k = n1 < n2 ? `${n1}-${n2}` : `${n2}-${n1}`;
          if (createdMuscles.has(k)) return;

          const node1 = nodes.find(n => n.id === n1);
          const node2 = nodes.find(n => n.id === n2);
          if (!node1 || !node2) return;

          const dist = VectorOps.distance(node1.pos, node2.pos);
          muscles.push({
              id: `m_${k}`,
              nodeA: n1,
              nodeB: n2,
              baseLength: dist,
              stiffness: stiffness, 
              dnaIndex: muscles.length,
              phase: Math.random() * Math.PI * 2,
              freq: 1.0,
              amp: 0.0,
              currentLength: dist,
              targetLength: dist
          });
          createdMuscles.add(k);
      };

      activeCells.forEach(c => {
          const myId = coordToNodeId.get(`${c.x},${c.y},${c.z}`);
          if (!myId) return;

          const neighbors = strategy.getNeighbors(c);
          neighbors.forEach(n => {
              const nid = coordToNodeId.get(`${n.coord.x},${n.coord.y},${n.coord.z}`);
              if (nid) {
                  addMuscle(myId, nid, 1.0);
              }
          });
      });

      // 4. Brain Grafting
      let genome: NeuralGenome;

      if (source && source.neuralGenome) {
          // Resize the brain if muscle count changed
          const oldG = source.neuralGenome;
          const newMusclesCount = muscles.length;
          const newNodesCount = nodes.length;

          // Helper to resize array
          const resize = (arr: number[], size: number) => {
              const res = new Array(size).fill(0);
              for(let i=0; i<Math.min(arr.length, size); i++) res[i] = arr[i];
              // Fill rest with random
              for(let i=arr.length; i<size; i++) res[i] = (Math.random()*1.0)-0.5;
              return res;
          };

          genome = {
              ...oldG,
              synapseWeights: resize(oldG.synapseWeights, newMusclesCount * 2), // Rough heuristic
              reservoirWeights: [...oldG.reservoirWeights], // Fixed size usually
              outputWeights: resize(oldG.outputWeights, newMusclesCount * 20),
              gripWeights: resize(oldG.gripWeights || [], newNodesCount * 20),
              biases: resize(oldG.biases, newNodesCount)
          };

      } else {
          // New Brain
          genome = this.geneticOperator.createRandomGenome(muscles.length, nodes.length);
      }

      for(let i=0; i<muscles.length; i++) muscles[i].dnaIndex = i;

      return {
          id,
          shape: this.type,
          nodes,
          muscles,
          neuralGenome: genome,
          fitness: 0,
          generation: 1,
          energy: 100,
          maxEnergy: 100,
          hungerTime: 0,
          isAlive: true,
          foodEaten: 0,
          visibleFood: [],
          initialHeadPos,
          distanceTraveled: 0,
          headNode // Cache
      };
  }
}

import { BioPhysicsEngine } from '../domain/BioPhysicsEngine';
import { Organism, ShapeType, NeuralGenome, FoodItem, Node, Muscle } from '../domain/types';
import { ShapeFactory } from '../domain/ShapeFactory';
import { VectorOps } from '../domain/math';
import { GeneticOperator } from '../domain/genetics/GeneticOperator';
import { IFitnessEvaluator, StandardFitnessEvaluator } from '../domain/fitness/FitnessEvaluator';
import { BrainController } from '../domain/neural/BrainController';

export class EvolutionService {
  public population: Organism[] = [];
  public currentGeneration = 1;
  public simulationTime = 0;

  private engine: BioPhysicsEngine;
  private geneticOperator: GeneticOperator;
  private fitnessEvaluator: IFitnessEvaluator;

  private populationSize = 20;
  private template: Organism | null = null; 

  private readonly START_ENERGY = 100;
  private readonly BASE_DECAY = 4.0; 
  private readonly HUNGER_ACCEL = 1.15; 
  private readonly FOOD_ENERGY = 30;

  // Updated: Magnet defaults to same as eat radius for visual consistency
  public magnetRadius = 0.8; 
  private readonly MAGNET_FORCE = 0.8;  
  public eatRadius = 0.8;    

  public foodSpawnCount = 25; // REDUCED FROM 50 FOR PERFORMANCE
  public foodSpawnRadius = 3.5;

  // NEW: Precise Food Vertical Control
  public foodSpawnMinHeight = 0.5;
  public foodSpawnMaxHeight = 3.0;

  // NEW: Dynamic Vision Radius
  public globalVisionRadius = 4.0;

  private updateListeners: ((pop: Organism[], time: number) => void)[] = [];
  private genCompleteListeners: ((best: Organism, gen: number) => void)[] = [];
  private newGenListeners: ((pop: Organism[]) => void)[] = [];

  constructor() {
    this.engine = new BioPhysicsEngine();
    this.geneticOperator = new GeneticOperator(0.05); // 5% mutation rate
    this.fitnessEvaluator = new StandardFitnessEvaluator();
  }

  public setGlobalStiffness(val: number) {
      this.engine.setConfig({ globalStiffness: val });
  }

  public setGlobalContractility(val: number) {
      this.engine.setConfig({ globalContractility: val });
  }

  public set foodWeight(val: number) {
      this.fitnessEvaluator.setWeights(val, (this.fitnessEvaluator as any).distanceWeight);
  }
  public get foodWeight(): number { return (this.fitnessEvaluator as any).foodWeight; }

  public set distanceWeight(val: number) {
       this.fitnessEvaluator.setWeights((this.fitnessEvaluator as any).foodWeight, val);
  }
  public get distanceWeight(): number { return (this.fitnessEvaluator as any).distanceWeight; }

  public updateFoodDistribution(): void {
      this.population.forEach(org => {
          org.visibleFood = this.generateFoodTrack(org);
      });
  }

  public initializePopulation(shape: ShapeType): void {
    this.template = ShapeFactory.create(shape, 'template');
    this.spawnGenerationFromTemplate(true);
  }

  public setTemplateAndReset(organism: Organism, startGeneration: number = 1): void {
      // Deep copy for the master template to ensure it's clean
      const safeJson = JSON.stringify(organism, (key, value) => {
          if (key === 'brain') return undefined;
          if (key === 'nodeRefA' || key === 'nodeRefB') return undefined;
          if (key === 'headNode') return undefined; // Avoid circular ref or re-finding
          return value;
      });
      this.template = JSON.parse(safeJson);

      // Re-bind headNode if missing from JSON
      if (!this.template!.headNode) {
          this.template!.headNode = this.template!.nodes.find(n => n.isHead);
      }

      this.currentGeneration = startGeneration;
      this.spawnGenerationFromTemplate(false); 
  }

  private cleanupCurrentPopulation() {
      // Explicitly break references to prevent leaks
      this.population.forEach(org => {
          if (org.brain && typeof org.brain.dispose === 'function') {
              org.brain.dispose();
          }
          org.brain = undefined;
      });
  }

  private spawnGenerationFromTemplate(resetGen: boolean): void {
      if (!this.template) return;

      this.cleanupCurrentPopulation();

      this.population = [];
      if (resetGen) this.currentGeneration = 1;
      this.simulationTime = 0;

      for (let i = 0; i < this.populationSize; i++) {
          const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${i}`);

          if (i > 0) {
              this.geneticOperator.mutateGenome(child.neuralGenome);
          }

          child.visibleFood = this.generateFoodTrack(child);
          this.fitnessEvaluator.evaluate(child, 0.016);

          this.population.push(child);
      }

      this.notifyNewGeneration(this.population);
  }

  private generateFoodTrack(organism: Organism): FoodItem[] {
      const food: FoodItem[] = [];
      const numFood = this.foodSpawnCount; 

      let centerX = 0;
      let centerZ = 0;

      // OPTIMIZATION: Use cached headNode
      const head = organism.headNode;

      if (head) {
          centerX = head.pos.x;
          centerZ = head.pos.z;
      }

      const spread = this.foodSpawnRadius; 

      // Vertical Range Logic
      const minY = this.foodSpawnMinHeight;
      const maxY = Math.max(minY, this.foodSpawnMaxHeight);
      const rangeY = maxY - minY;

      for(let i=0; i<numFood; i++) {
          const theta = Math.random() * Math.PI * 2;
          const radius = 1.0 + Math.random() * spread; 
          const x = centerX + Math.cos(theta) * radius;
          const z = centerZ + Math.sin(theta) * radius;

          // Use configurable height range
          const y = minY + Math.random() * rangeY;

          food.push({
              id: `f_${i}`,
              pos: { x, y, z },
              energyValue: this.FOOD_ENERGY,
              consumed: false
          });
      }
      return food;
  }

  public getBestOrganism(): Organism | null {
      if (this.population.length === 0) return null;
      const sorted = [...this.population].sort((a, b) => b.fitness - a.fitness);
      const best = sorted[0];

      const safeJson = JSON.stringify(best, (key, value) => {
          if (key === 'brain') return undefined;
          if (key === 'nodeRefA' || key === 'nodeRefB') return undefined;
          if (key === 'headNode') return undefined;
          return value;
      });
      const cleanCopy = JSON.parse(safeJson);
      cleanCopy.generation = this.currentGeneration;

      return cleanCopy;
  }

  public getLeader(): Organism | null {
      if (this.population.length === 0) return null;

      let bestAlive: Organism | null = null;
      let maxZAlive = -Infinity;

      let bestDead: Organism | null = null;
      let maxZDead = -Infinity;

      for (const org of this.population) {
          let cz = 0;
          for(const n of org.nodes) cz += n.pos.z;
          cz /= org.nodes.length;

          if (org.isAlive) {
              if (cz > maxZAlive) { maxZAlive = cz; bestAlive = org; }
          } else {
              if (cz > maxZDead) { maxZDead = cz; bestDead = org; }
          }
      }

      return bestAlive || bestDead || this.population[0];
  }

  public step(dt: number): void {
    this.simulationTime += dt;
    this.updatePhysics(dt, false);
    this.updateMetabolism(dt);

    if (Math.floor(this.simulationTime * 100) % 100 === 0) {
        this.applySocialLearning();
    }

    const allDead = !this.population.some(org => org.isAlive);
    if (allDead) {
        this.evolve();
    }

    this.notifyUpdate(this.population, this.simulationTime);
  }

  private applySocialLearning() {
      const sorted = [...this.population].sort((a, b) => b.fitness - a.fitness);
      if (sorted.length < 2) return;

      const leader = sorted[0];
      const bottomHalfStart = Math.floor(sorted.length / 2);

      for(let i=0; i<sorted.length; i++) {
         // Everyone learns a little bit from the leader
         if (i === 0) continue;
         const learner = sorted[i];
         if (!learner.isAlive) continue;

         const learningRate = 0.01; 
         const lg = learner.neuralGenome;
         const bg = leader.neuralGenome;

         for(let k=0; k<lg.synapseWeights.length; k++) {
             if (bg.synapseWeights[k] !== undefined) {
                 lg.synapseWeights[k] += (bg.synapseWeights[k] - lg.synapseWeights[k]) * learningRate;
             }
         }
      }
  }

  private updatePhysics(dt: number, fastMode: boolean): void {
    this.population.forEach(org => {
      // 1. DEAD CHECK: Remove from calculations (Frozen Statue Logic)
      if (!org.isAlive) return;

      // 2. BRAIN UPDATE
      if (!org.brain) {
          org.brain = new BrainController(org);
      }
      const contractility = (this.engine as any).config.globalContractility;
      // Pass dynamic vision radius to brain
      org.brain.update(dt, contractility, this.globalVisionRadius);

      // 3. PHYSICS UPDATE
      this.engine.updateOrganism(org, this.simulationTime, fastMode);
    });
  }

  private updateMetabolism(dt: number): void {
      this.population.forEach(org => {
          // 1. Calculate Fitness
          this.fitnessEvaluator.evaluate(org, dt);

          if (!org.isAlive) return;

          org.hungerTime += dt;
          const hungerMultiplier = Math.pow(this.HUNGER_ACCEL, org.hungerTime);
          const loss = this.BASE_DECAY * hungerMultiplier * dt;
          org.energy -= loss;

          if (org.energy <= 0) {
              org.energy = 0;
              org.isAlive = false;
              return; 
          }

          // OPTIMIZATION: Use Cached Head
          let head = org.headNode;

          // Self-heal just in case
          if (!head && org.nodes.length > 0) {
              head = org.nodes.find(n => n.isHead);
              if (!head) head = org.nodes[0];
              org.headNode = head;
          }

          if (head) {
            for (const food of org.visibleFood) {
                if (food.consumed) continue;

                // INLINED MATH (Optimized)
                // Avoid VectorOps.distance and VectorOps.sub object creation
                const dx = head.pos.x - food.pos.x;
                const dy = head.pos.y - food.pos.y;
                const dz = head.pos.z - food.pos.z;
                const distSq = dx*dx + dy*dy + dz*dz;

                // Fast reject check (Squared)
                // Use dynamic magnetRadius
                if (distSq < this.magnetRadius * this.magnetRadius) {
                    const dist = Math.sqrt(distSq);

                    // --- NAN GUARD: PREVENT MERGE SINGULARITY ---
                    // If food is sucked into the EXACT same coordinate as head (dist=0),
                    // the physics/vision vectors will become NaN (div by zero).
                    // We prevent this by gently nudging the food away if it gets too close.
                    if (dist < 0.0001) {
                         food.pos.x += 0.01; 
                         // Recalculate will happen next frame, preventing the NaN now.
                         continue;
                    }

                    // Pull Force
                    const strength = 1.0 - (dist / this.magnetRadius);
                    const force = this.MAGNET_FORCE * (1.0 + strength);

                    // Apply directly (Pull vector is -diff vector)
                    // pull = head - food. so dx = head.x - food.x
                    food.pos.x += dx * force * 0.1;
                    food.pos.y += dy * force * 0.1;
                    food.pos.z += dz * force * 0.1;

                    // Recheck Distance (Cheap approximation: assume it moved closer)
                    const ndx = head.pos.x - food.pos.x;
                    const ndy = head.pos.y - food.pos.y;
                    const ndz = head.pos.z - food.pos.z;
                    const nDistSq = ndx*ndx + ndy*ndy + ndz*ndz;

                    // Use dynamic eatRadius
                    if (nDistSq < this.eatRadius * this.eatRadius) {
                        food.consumed = true;
                        org.energy += food.energyValue;
                        if (org.energy > org.maxEnergy) org.energy = org.maxEnergy;
                        org.hungerTime = 0;
                        org.foodEaten++;
                    }
                }
            }
          }
      });
  }

  private finalizeFitness() {
      this.population.forEach(org => this.fitnessEvaluator.finalize(org));
  }

  public evolve(): void {
    if (!this.template) return;

    this.finalizeFitness(); 

    // 1. Selection
    this.population.sort((a, b) => b.fitness - a.fitness);
    const survivorsCount = Math.floor(this.populationSize * 0.25);
    const survivors = this.population.slice(0, survivorsCount);
    const bestOrganism = survivors[0];

    this.notifyGenComplete(bestOrganism, this.currentGeneration);

    // 2. Reproduction
    this.currentGeneration++;
    const nextGen: Organism[] = [];

    // Elitism
    const champion = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_champ`);
    champion.neuralGenome = this.geneticOperator.cloneGenome(bestOrganism.neuralGenome);
    champion.visibleFood = this.generateFoodTrack(champion);
    this.fitnessEvaluator.evaluate(champion, 0.016);
    nextGen.push(champion);

    // Fill
    while (nextGen.length < this.populationSize) {
      const parent = survivors[Math.floor(Math.random() * survivors.length)];
      const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${nextGen.length}`);
      child.neuralGenome = this.geneticOperator.cloneGenome(parent.neuralGenome);
      this.geneticOperator.mutateGenome(child.neuralGenome);
      child.visibleFood = this.generateFoodTrack(child);
      this.fitnessEvaluator.evaluate(child, 0.016);
      nextGen.push(child);
    }

    // Cleanup Old Population before switching
    this.cleanupCurrentPopulation();

    this.population = nextGen;
    this.simulationTime = 0;

    this.notifyNewGeneration(this.population);
  }

  private createOrganismFromTemplate(template: Organism, newId: string): Organism {
      // 1. Clone Nodes
      const newNodes: Node[] = template.nodes.map(n => ({
          ...n,
          pos: { ...n.pos },
          oldPos: { ...n.pos }, 
          activation: 0,
          gripSignal: 0,
          isGripping: false
      }));

      // 2. Clone Muscles
      const newMuscles: Muscle[] = template.muscles.map(m => ({
          ...m,
          currentLength: undefined,
          targetLength: undefined,
          phase: Math.random() * Math.PI * 2,
          nodeRefA: undefined,
          nodeRefB: undefined
      }));

      // 3. Clone Genome 
      const newGenome = this.geneticOperator.cloneGenome(template.neuralGenome);

      // 4. Construct
      const clone: Organism = {
          id: newId,
          shape: template.shape,
          nodes: newNodes,
          muscles: newMuscles,
          neuralGenome: newGenome,
          fitness: 0,
          generation: 1,
          brain: undefined,

          energy: this.START_ENERGY,
          maxEnergy: this.START_ENERGY,
          hungerTime: 0,
          isAlive: true,
          foodEaten: 0,
          visibleFood: [],

          // Distance Stats
          initialHeadPos: template.initialHeadPos ? { ...template.initialHeadPos } : {x:0,y:0,z:0},
          distanceTraveled: 0
      };

      // Safety check for starting pos if template was malformed
      if (!clone.initialHeadPos) {
           const head = clone.nodes.find(n => n.isHead);
           clone.initialHeadPos = head ? { ...head.pos } : { x: 0, y: 0, z: 0 };
      }

      // OPTIMIZATION: Cache Head
      const head = clone.nodes.find(n => n.isHead);
      if (head) clone.headNode = head;

      return clone;
  }

  public subscribe(type: 'update', cb: (pop: Organism[], time: number) => void): () => void;
  public subscribe(type: 'genComplete', cb: (best: Organism, gen: number) => void): () => void;
  public subscribe(type: 'newGen', cb: (pop: Organism[]) => void): () => void;
  public subscribe(type: string, cb: any): () => void {
      if (type === 'update') {
          this.updateListeners.push(cb);
          return () => this.updateListeners = this.updateListeners.filter(l => l !== cb);
      }
      if (type === 'genComplete') {
          this.genCompleteListeners.push(cb);
          return () => this.genCompleteListeners = this.genCompleteListeners.filter(l => l !== cb);
      }
      if (type === 'newGen') {
          this.newGenListeners.push(cb);
          return () => this.newGenListeners = this.newGenListeners.filter(l => l !== cb);
      }
      return () => {};
  }

  public onUpdate(cb: (pop: Organism[], time: number) => void) { this.subscribe('update', cb); }
  public onGenComplete(cb: (best: Organism, gen: number) => void) { this.subscribe('genComplete', cb); }
  public onNewGeneration(cb: (pop: Organism[]) => void) { this.subscribe('newGen', cb); }

  private notifyUpdate(pop: Organism[], time: number) { this.updateListeners.forEach(l => l(pop, time)); }
  private notifyGenComplete(best: Organism, gen: number) { this.genCompleteListeners.forEach(l => l(best, gen)); }
  private notifyNewGeneration(pop: Organism[]) { this.newGenListeners.forEach(l => l(pop)); }
}

import { useEffect, useRef, useState, useCallback } from 'react';
import { EvolutionService } from './EvolutionService';
import { ShapeType, Organism } from '../domain/types';

export function useEvolutionLoop() {
  const serviceRef = useRef<EvolutionService>(new EvolutionService());
  const requestRef = useRef<number>(0);

  const [population, setPopulation] = useState<Organism[]>([]);
  const [generation, setGeneration] = useState(1);
  const [currentShape, setCurrentShape] = useState<ShapeType>(ShapeType.CUBE);
  const [isRunning, setIsRunning] = useState(false);
  const [isFastForward, setIsFastForward] = useState(false);

  // STATS STATE - OPTIMIZED: We now share a REF, not a state, for high frequency updates
  const [fitnessHistory, setFitnessHistory] = useState<number[]>([]);
  const statsRef = useRef({ fitness: 0, foodEaten: 0, distance: 0 });

  // New Physics State (Updated Defaults)
  const [globalStiffness, setGlobalStiffnessState] = useState(0.8);
  const [globalContractility, setGlobalContractilityState] = useState(1.5);

  // Fitness Weights Configuration (Updated Defaults)
  const [foodWeight, setFoodWeightState] = useState(20.0);
  const [distanceWeight, setDistanceWeightState] = useState(20.0);

  // Scarcity Controls
  const [foodSpawnCount, setFoodSpawnCountState] = useState(50);
  const [foodSpawnRadius, setFoodSpawnRadiusState] = useState(3.5);
  // NEW: Food Vertical Range
  const [foodSpawnMinHeight, setFoodSpawnMinHeightState] = useState(0.5);
  const [foodSpawnMaxHeight, setFoodSpawnMaxHeightState] = useState(3.0);

  // Vision Control
  const [visionRadius, setVisionRadiusState] = useState(4.0);
  const [eatRadius, setEatRadiusState] = useState(0.8);

  // Initialize
  useEffect(() => {
    const service = serviceRef.current;

    // Wire up listeners
    // Removed the High Frequency Update State trigger
    const unsubUpdate = service.subscribe('update', (pop, time) => {
        // Just update the REF. Do NOT trigger a re-render.
        // The StatsOverlay component will poll this ref via requestAnimationFrame
        const leader = service.getLeader();
        if (leader) {
            statsRef.current.fitness = leader.fitness;
            statsRef.current.foodEaten = leader.foodEaten;
            statsRef.current.distance = leader.distanceTraveled || 0;
        }
    });

    const unsubGen = service.subscribe('genComplete', (best, gen) => {
        setGeneration(gen);
        // Track History
        setFitnessHistory(prev => [...prev, best.fitness]);
    });

    const unsubNewGen = service.subscribe('newGen', (newPop) => {
        setPopulation([...newPop]);
    });

    service.initializePopulation(currentShape);
    setPopulation([...service.population]); // Initial sync

    return () => {
        cancelAnimationFrame(requestRef.current!);
        unsubUpdate();
        unsubGen();
        unsubNewGen();
    };
  }, []);

  const reset = useCallback((shape: ShapeType) => {
    setIsRunning(false);
    setIsFastForward(false);
    setCurrentShape(shape);
    serviceRef.current.initializePopulation(shape);
    setPopulation([...serviceRef.current.population]);
    setGeneration(1);
    statsRef.current = { fitness: 0, foodEaten: 0, distance: 0 };
    setFitnessHistory([]);
  }, []);

  const spawnCustom = useCallback((organism: Organism, autoStart: boolean = false) => {
      serviceRef.current.setTemplateAndReset(organism);
      setPopulation([...serviceRef.current.population]);
      setGeneration(1);
      statsRef.current = { fitness: 0, foodEaten: 0, distance: 0 };
      setFitnessHistory([]); // Clear history on new spawn
      setCurrentShape(organism.shape);

      setIsRunning(autoStart);
      setIsFastForward(false);
  }, []);

  const evolve = useCallback(() => {
    serviceRef.current.evolve();
    setPopulation([...serviceRef.current.population]); // Update React view
    setGeneration(serviceRef.current.currentGeneration);
  }, []);

  // --- PHYSICS CONTROL HANDLERS ---
  const setGlobalStiffness = useCallback((val: number) => {
      setGlobalStiffnessState(val);
      serviceRef.current.setGlobalStiffness(val);
  }, []);

  const setGlobalContractility = useCallback((val: number) => {
      setGlobalContractilityState(val);
      serviceRef.current.setGlobalContractility(val);
  }, []);

  // --- FITNESS WEIGHT HANDLERS ---
  const setFoodWeight = useCallback((val: number) => {
      setFoodWeightState(val);
      serviceRef.current.foodWeight = val;
  }, []);

  const setDistanceWeight = useCallback((val: number) => {
      setDistanceWeightState(val);
      serviceRef.current.distanceWeight = val;
  }, []);

  // --- SCARCITY HANDLERS ---
  const setFoodSpawnCount = useCallback((val: number) => {
      setFoodSpawnCountState(val);
      serviceRef.current.foodSpawnCount = val;
      serviceRef.current.updateFoodDistribution(); // Real-time update
  }, []);

  const setFoodSpawnRadius = useCallback((val: number) => {
      setFoodSpawnRadiusState(val);
      serviceRef.current.foodSpawnRadius = val;
      serviceRef.current.updateFoodDistribution(); // Real-time update
  }, []);

  const setFoodSpawnMinHeight = useCallback((val: number) => {
      setFoodSpawnMinHeightState(val);
      serviceRef.current.foodSpawnMinHeight = val;
      serviceRef.current.updateFoodDistribution();
  }, []);

  const setFoodSpawnMaxHeight = useCallback((val: number) => {
      setFoodSpawnMaxHeightState(val);
      serviceRef.current.foodSpawnMaxHeight = val;
      serviceRef.current.updateFoodDistribution();
  }, []);


  // --- VISION HANDLER ---
  const setVisionRadius = useCallback((val: number) => {
      setVisionRadiusState(val);
      serviceRef.current.globalVisionRadius = val;
  }, []);

  // --- MOUTH HANDLER ---
  const setEatRadius = useCallback((val: number) => {
      setEatRadiusState(val);
      serviceRef.current.eatRadius = val;
      serviceRef.current.magnetRadius = val;
  }, []);


  // --- DATA IO ---

  const saveCreature = useCallback(() => {
    const best = serviceRef.current.getBestOrganism();
    if (!best) return;

    const json = JSON.stringify(best, null, 2);
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `creature_gen${best.generation}_${Date.now()}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }, []);

  const loadCreature = useCallback((file: File, onLoaded?: (org: Organism) => void) => {
      const reader = new FileReader();
      reader.onload = (e) => {
          try {
              const json = e.target?.result as string;
              const organism = JSON.parse(json) as Organism;

              if (!organism.nodes || !organism.muscles || !organism.neuralGenome) {
                  alert("Invalid Creature File");
                  return;
              }

              spawnCustom(organism, false);

              // Notify App
              if (onLoaded) onLoaded(organism);

          } catch (err) {
              console.error(err);
              alert("Failed to load creature file.");
          }
      };
      reader.readAsText(file);
  }, [spawnCustom]);


  // --- MAIN LOOP ---

  const toggleAutoEvolve = useCallback(() => {
      setIsFastForward(prev => !prev);
      // If we fast forward, we ensure we are running
      if (!isFastForward) setIsRunning(true); 
  }, [isFastForward]);

  const loop = useCallback(() => {
    if (!isRunning) return;

    // FAST FORWARD LOGIC:
    const iterations = isFastForward ? 8 : 1;

    for(let i=0; i<iterations; i++) {
        serviceRef.current.step(0.016);
    }

    requestRef.current = requestAnimationFrame(loop);
  }, [isRunning, isFastForward]);

  useEffect(() => {
    if (isRunning) {
      requestRef.current = requestAnimationFrame(loop);
    } else {
      cancelAnimationFrame(requestRef.current!);
    }
    return () => cancelAnimationFrame(requestRef.current!);
  }, [isRunning, loop]);

  return {
    population,
    generation,
    statsRef, // EXPOSED REF INSTEAD OF STATE
    fitnessHistory,
